/*
 * RISC-V 64 链接脚本
 * 
 * 内存布局 for QEMU virt 平台:
 * - RAM 起始地址: 0x8000_0000
 * - OpenSBI 占用前 2MB
 * - 内核加载到: 0x8020_0000
 */

OUTPUT_ARCH(riscv)
ENTRY(_start)

BASE_ADDRESS = 0x80200000;

SECTIONS
{
    . = BASE_ADDRESS;

    /* 代码段 */
    .text : {
        _text_start = .;
        *(.text.entry)    /* 入口点必须在最前面 */
        *(.text .text.*)
        _text_end = .;
    }

    /* 只读数据段 */
    .rodata : ALIGN(4K) {
        _rodata_start = .;
        *(.rodata .rodata.*)
        *(.srodata .srodata.*)
        _rodata_end = .;
    }

    /* 数据段 */
    .data : ALIGN(4K) {
        _data_start = .;
        *(.data .data.*)
        *(.sdata .sdata.*)
        _data_end = .;
    }

    /* BSS 段 (未初始化数据) */
    .bss : ALIGN(4K) {
        _bss_start = .;
        *(.bss .bss.*)
        *(.sbss .sbss.*)
        _bss_end = .;
    }

    /* 栈空间 (256KB) — 需要足够大以容纳 TCB 构造等深栈操作 */
    . = ALIGN(4K);
    _stack_bottom = .;
    . += 256K;
    _stack_top = .;

    /* 内核结束地址 */
    _kernel_end = .;

    /* 丢弃不需要的段 */
    /DISCARD/ : {
        *(.eh_frame)
        *(.comment)
    }
}

//! RISC-V 64 启动代码
//!
//! 将 entry.S 汇编嵌入内核二进制, 定义 _start 入口点。
//! linker.ld 由 build.rs 设置。

core::arch::global_asm!(include_str!("entry.S"));

//! RISC-V 64 架构支持
//!
//! 子目录:
//!   boot/  — 启动汇编 (entry.S) + 链接脚本 (linker.ld)
//!   trap/  — 中断/异常处理 (Context + trap.S + Rust 分发 + 定时器)
//!   task/  — 任务切换 (TaskContext + switch.S)
//!   mmu/   — Sv39 页表管理 + MMU 激活
//!   cpu.rs — CPU 底层屏障指令

// ─── 启动代码 (entry.S 由 global_asm! 嵌入) ─────────────
mod boot;

// ─── SBI 接口封装 ────────────────────────────────────────
pub mod sbi;

// ─── 引导控制台 (bootstrap, 微内核成熟后移至用户态) ──
pub mod uart;

// ─── 中断控制器 ──────────────────────────────────────────
pub mod plic;

// ─── 中断开关 (SIE guard) — 实际实现在 trap/interrupt.rs ──
pub use trap::interrupt;

// ─── 中断/异常处理 ────────────────────────────────────────
pub mod trap;

// ─── 任务切换 ─────────────────────────────────────────────
pub mod task;

// ─── 内存管理单元 ─────────────────────────────────────────
pub mod mmu;
pub use mmu::paging::{kernel_satp, switch_satp};

// ─── CPU 底层操作（屏障指令，供 HAL 门面调用）───────────
pub mod cpu;

// ─── 架构抽象接口 ─────────────────────────────────────────

/// CPU 低功耗等待 (RISC-V: WFI - Wait For Interrupt)
///
/// 其他架构对应:
///   AArch64 → WFE
///   x86-64  → HLT
#[inline(always)]
pub fn halt() {
    unsafe {
        core::arch::asm!("wfi", options(nomem, nostack));
    }
}

/// arch/riscv64/trap/ — 中断/异常处理子系统
///
/// 组件:
///   context.rs — Trap Context (34×8=272 字节, 全部通用寄存器 + sstatus/sepc)
///   handler.rs — Rust 分发逻辑 (__trap_handler, handle_interrupt, handle_exception)
///   timer.rs   — S-mode 定时器 (SBI set_timer, 回调机制)
///   trap.S     — 汇编入口 (__trap_entry, __trap_return)
pub mod context;
pub mod handler;
pub mod interrupt;
pub mod timer;

#[allow(unused_imports)] // 供外部模块 (如 syscall) 将来使用
pub use context::Context;
pub use handler::init;
pub use handler::trap_return_addr;

/// arch/riscv64/trap/handler.rs — RISC-V S-mode 异常/中断分发
///
/// 去耦合设计:
///   arch 模块不直接依赖 sched/ 或 syscall/, 而是通过回调机制通信。
///   上层模块在初始化时通过 register_trap_callbacks() 注册处理函数。
///   这使得 arch/ 可以独立于内核策略层编译和测试。
///
/// sscratch 协议:
///   = 0        → 当前在 S-mode (嵌套 trap 保护)
///   = kernel_sp → 当前在 U-mode (用户态)
///
/// satp 协议:
///   进入 trap 时 satp 保持不变 (用户页表通过 splice 共享内核映射),
///   satp 切换仅在 __switch 时完成。
use super::context::Context;

// 将汇编代码嵌入到 Rust 模块中，定义 __trap_entry 和 __trap_return 两个符号
core::arch::global_asm!(include_str!("trap.S"));

// 定义函数将汇编函数外显为 Rust 可调用的函数指针
// 由于使用汇编C结构，需要使用extern "C" 来指定调用约定，并且函数名需要与汇编中的符号一致
unsafe extern "C" {
    fn __trap_entry();
    fn __trap_return();
}

/// 获取 __trap_return 地址 (用于 U-mode 任务初始入口)
pub fn trap_return_addr() -> usize {
    __trap_return as *const () as usize
}

// ═══════════════════════════════════════════════════════════
//  回调机制 — 解耦 arch 与上层模块 (sched / syscall)
// ═══════════════════════════════════════════════════════════

/// U-mode 异常类型 (架构无关, 供上层映射到具体信号)
#[derive(Copy, Clone, Debug)]
pub enum FaultKind {
    IllegalInstruction,
    PageFault,
    WritePageFault,
    AccessFault,
    Misaligned,
}

/// Trap 回调集合 — 由上层模块在初始化时注册
pub struct TrapCallbacks {
    /// 系统调用分发: (syscall_id, args) → 返回值
    pub syscall_dispatch: fn(usize, [usize; 6]) -> isize,
    /// 返回 U-mode 前的钩子 (如: 投递待处理信号)
    pub pre_return_to_user: fn(),
    /// U-mode 异常处理: (sepc, stval, fault_kind)
    pub user_fault: fn(usize, usize, FaultKind),
}

static mut TRAP_CALLBACKS: Option<TrapCallbacks> = None;

/// 注册 trap 回调 (由 main.rs 在初始化阶段调用, 仅一次)
pub fn register_trap_callbacks(cb: TrapCallbacks) {
    unsafe {
        TRAP_CALLBACKS = Some(cb);
    }
}

/// 获取已注册的回调 (init 后保证 Some)
#[inline(always)]
fn callbacks() -> &'static TrapCallbacks {
    unsafe { TRAP_CALLBACKS.as_ref().unwrap() }
}

// ═══════════════════════════════════════════════════════════
//  RISC-V 异常和中断常量
// ═══════════════════════════════════════════════════════════

const INTERRUPT_BIT: usize = 1usize << 63;
const SSTATUS_SPP: usize = 1 << 8;

// ===== 异常编号（scause 最高位=0 时的低位值）=====
// 完整列表见 RISC-V 特权级规范 Table 4.2
const EXC_INSTRUCTION_MISALIGNED: usize = 0; // 指令地址未对齐
const EXC_INSTRUCTION_FAULT: usize = 1; // 指令访问错误
const EXC_ILLEGAL_INSTRUCTION: usize = 2; // 非法指令
const EXC_BREAKPOINT: usize = 3; // ebreak 断点
const EXC_LOAD_FAULT: usize = 5; // 读内存错误
const EXC_STORE_FAULT: usize = 7; // 写内存错误
const EXC_ECALL_FROM_U: usize = 8; // 用户态 ecall（系统调用）
const EXC_ECALL_FROM_S: usize = 9; // 内核态 ecall
const EXC_INSTRUCTION_PAGE_FAULT: usize = 12; // 指令页错误
const EXC_LOAD_PAGE_FAULT: usize = 13; // 读页错误
const EXC_STORE_PAGE_FAULT: usize = 15; // 写页错误

// ===== 中断编号（scause 最高位=1 时的低位值）=====
const IRQ_S_SOFT: usize = 1; // 软件中断
const IRQ_S_TIMER: usize = 5; // 计时器中断
const IRQ_S_EXTERNAL: usize = 9; // 外部中断（PLIC）

// 异常/中断枚举enum
#[derive(Copy, Clone, Debug)]
enum Trap {
    Interrupt(Interrupt), // 中断类型
    Exception(Exception), // 异常类型
}

#[derive(Copy, Clone, Debug)]
#[allow(dead_code)] // Unknown 字段通过 Debug 输出使用
enum Interrupt {
    SupervisorSoft,     // 软件中断
    SupervisorTimer,    // 计时器中断
    SupervisorExternal, // 外部中断
    Unknown(usize),     // 保留原始编号，调试用 (暂未使用，但需保留字段用于未来日志)
}

#[derive(Copy, Clone, Debug)]
#[allow(dead_code)] // Unknown 字段通过 Debug 输出使用
enum Exception {
    InstructionMisaligned, // 指令地址未对齐
    InstructionFault,      // 指令访问错误
    IllegalInstruction,    // 非法指令

    Breakpoint,           // ebreak 断点
    LoadFault,            // 读内存错误
    StoreFault,           // 写内存错误
    EcallFromU,           // 用户态 ecall
    EcallFromS,           // 内核态 ecall
    InstructionPageFault, // 指令页错误
    LoadPageFault,        // 读页错误
    StorePageFault,       // 写页错误
    Unknown(usize),       // 保留原始编号，调试用
}

// 核心函数
#[no_mangle]
pub extern "C" fn __trap_handler(ctx: &mut Context) -> *mut Context {
    let scause = read_scause();
    let stval = read_stval();
    let trap = decode_trap(scause);
    let from_user = context_from_user(ctx);

    match trap {
        Trap::Interrupt(irq) => handle_interrupt(irq, ctx),
        Trap::Exception(exc) => handle_exception(exc, ctx, stval),
    }

    // 返回用户态前, 调用注册的钩子 (如信号投递)。
    // U-mode 入口由 trap.S 在 x[0] 写入非零标记；若保存的 sstatus.SPP
    // 被栈/内存破坏，这个标记仍能阻止 __trap_return 误以 S-mode sret。
    if from_user {
        ctx.sstatus &= !SSTATUS_SPP;
        let cb = callbacks();
        (cb.pre_return_to_user)();
    }

    // 断言: ctx 指针必须正好位于 kstack_top - CTX_SIZE 处。
    // 若 ctx 偏移错误，__trap_return 会将错误值写入 sscratch，
    // 导致下次 U-mode trap 时 sp 指向非法地址，引发嵌套 page fault。
    if from_user {
        let ctx_addr = ctx as *mut Context as usize;
        let kstack_top = crate::sched::query::current_kstack_top();
        let ctx_size = core::mem::size_of::<Context>();
        if kstack_top != 0 && ctx_addr + ctx_size != kstack_top {
            panic!(
                "trap_handler: ctx={:#x} + ctx_size={:#x} = {:#x} != kstack_top={:#x} (pid={})",
                ctx_addr, ctx_size, ctx_addr + ctx_size, kstack_top,
                crate::sched::query::current_pid(),
            );
        }
    }

    // 安全校验: U-mode 返回前 sepc 必须是合法用户地址。
    // sepc=0 或 sepc >= 0x8000_0000 → sret 后 S-mode InstructionPageFault 或内核代码执行。
    // 以 SIGSEGV(11) 终止进程: 退出码 128+11=139, 符合 POSIX "被信号终止" 编码。
    if from_user {
        let sepc = ctx.sepc;
        if sepc == 0 || sepc >= 0x8000_0000 {
            crate::kwarn!(
                "trap_handler: invalid U-mode sepc={:#x}, ra={:#x}, pid={} — SIGSEGV",
                sepc, ctx.x[1], crate::sched::query::current_pid(),
            );
            crate::sched::lifecycle::exit_current(128 + 11, Some(11));
        }
    }

    ctx as *mut Context
}

/// 中断处理: 定时器 / 软件中断 / 外部中断 (PLIC)
fn handle_interrupt(irq: Interrupt, ctx: &mut Context) {
    match irq {
        Interrupt::SupervisorTimer => {
            // 只有来自 U-mode 的 timer trap 才允许抢占调度。
            // S-mode 内核栈上的任意 Rust 帧不保证可被 timer 直接切走；
            // 这些路径仍通过 yield/block/exit 等显式调度点切换。
            super::timer::on_tick(context_from_user(ctx));
        }
        Interrupt::SupervisorSoft => {
            // 清除 SSIP, 否则中断会重复触发
            unsafe {
                core::arch::asm!(
                    "csrc sip, {ssip}",
                    ssip = in(reg) 1usize << 1,
                    options(nostack, nomem),
                );
            }
        }
        Interrupt::SupervisorExternal => {
            let irq_id = crate::arch::plic::claim();
            if irq_id != 0 {
                match irq_id {
                    crate::arch::plic::UART_IRQ => crate::arch::uart::handle_irq(),
                    _ => crate::kwarn!("unknown IRQ {}", irq_id),
                }
                crate::arch::plic::complete(irq_id);
            }
        }
        Interrupt::Unknown(_) => {}
    }
}

/// 异常处理: 系统调用 / 页错误 / 非法指令等
fn handle_exception(exc: Exception, ctx: &mut Context, stval: usize) {
    match exc {
        Exception::Breakpoint => {
            ctx.sepc = ctx.sepc.wrapping_add(4);
        }
        Exception::EcallFromU => {
            let is_sigreturn = handle_syscall(ctx);
            if !is_sigreturn {
                ctx.sepc = ctx.sepc.wrapping_add(4);
            }
        }
        Exception::EcallFromS => {
            panic!("Unexpected ecall from S-mode, sepc={:#x}", ctx.sepc);
        }
        Exception::InstructionPageFault
        | Exception::LoadPageFault
        | Exception::StorePageFault
        | Exception::InstructionFault
        | Exception::LoadFault
        | Exception::StoreFault
        | Exception::IllegalInstruction
        | Exception::InstructionMisaligned => {
            // sstatus.SPP=0 → 来自 U-mode, SPP=1 → 来自 S-mode。
            let from_user = context_from_user(ctx);
            if from_user {
                let kind = match exc {
                    Exception::IllegalInstruction => FaultKind::IllegalInstruction,
                    Exception::InstructionPageFault
                    | Exception::LoadPageFault => 

[... truncated 4734 chars ...]

/// Trap 上下文 — 中断/异常时保存全部寄存器 (34 × 8 = 272 字节)
///
/// 由 trap.S 中 __trap_entry / __trap_return 通过固定偏移量操作,
/// 必须使用 #[repr(C)] 保证内存布局。
///
/// 不包含浮点/向量寄存器 (F/V 扩展), 后续按硬件能力条件启用。
#[repr(C)]
pub struct Context {
    pub x: [usize; 32], // 通用寄存器 x0-x31
    pub sstatus: usize,
    pub sepc: usize,
}

                "[trap] 未处理异常 {:?}, sepc={:#x}, stval={:#x}",
                exc, ctx.sepc, stval
            );
        }
    }
}

#[inline(always)]
fn context_from_user(ctx: &Context) -> bool {
    ctx.sstatus & SSTATUS_SPP == 0 || ctx.x[0] != 0
}

/// 系统调用分发 (通过回调, 不直接依赖 syscall 模块)
fn handle_syscall(ctx: &mut Context) -> bool {
    let id = ctx.x[17]; // a7 = syscall 编号
    let args = [
        ctx.x[10], ctx.x[11], ctx.x[12], // a0, a1, a2
        ctx.x[13], ctx.x[14], ctx.x[15], // a3, a4, a5
    ];

    let cb = callbacks();

    // rt_sigreturn 需要特殊处理: 恢复整个 TrapContext, 跳过 sepc += 4
    const SYS_RT_SIGRETURN: usize = 139;
    if id == SYS_RT_SIGRETURN {
        (cb.syscall_dispatch)(id, args);
        return true;
    }

    let ret = (cb.syscall_dispatch)(id, args);
    ctx.x[10] = ret as usize; // 返回值写回 a0
    false
}

// ═══════════════════════════════════════════════════════════
//  初始化 + CSR 工具函数
// ═══════════════════════════════════════════════════════════

/// 初始化 stvec / sscratch / ssie
pub fn init() {
    let trap_entry = __trap_entry as *const () as usize;
    unsafe {
        // stvec: Direct 模式 (低 2 位 = 00)
        core::arch::asm!("csrw stvec, {}", in(reg) trap_entry, options(nostack, nomem));
        // sscratch = 0: 标记当前在 S-mode (启动时内核在 S-mode)
        core::arch::asm!("csrw sscratch, zero", options(nostack, nomem));
        // 启用 SSIE (S-mode Software Interrupt Enable), sie bit 1
        core::arch::asm!(
            "csrs sie, {ssie}",
            ssie = in(reg) 1usize << 1,
            options(nostack, nomem),
        );
    }
}

fn read_scause() -> usize {
    let scause: usize;
    unsafe {
        core::arch::asm!("csrr {}, scause", out(reg) scause, options(nostack, nomem));
    }
    scause
}

fn read_stval() -> usize {
    let stval: usize;
    unsafe {
        core::arch::asm!("csrr {}, stval", out(reg) stval, options(nostack, nomem));
    }
    stval
}

fn decode_trap(scause: usize) -> Trap {
    if scause & INTERRUPT_BIT != 0 {
        let irq_num = scause & !INTERRUPT_BIT;
        let irq = match irq_num {
            IRQ_S_SOFT => Interrupt::SupervisorSoft,
            IRQ_S_TIMER => Interrupt::SupervisorTimer,
            IRQ_S_EXTERNAL => Interrupt::SupervisorExternal,
            _ => Interrupt::Unknown(irq_num),
        };
        Trap::Interrupt(irq)
    } else {
        let exc_num = scause;
        let exc = match exc_num {
            EXC_INSTRUCTION_MISALIGNED => Exception::InstructionMisaligned,
            EXC_INSTRUCTION_FAULT => Exception::InstructionFault,
            EXC_ILLEGAL_INSTRUCTION => Exception::IllegalInstruction,
            EXC_BREAKPOINT => Exception::Breakpoint,
            EXC_LOAD_FAULT => Exception::LoadFault,
            EXC_STORE_FAULT => Exception::StoreFault,
            EXC_ECALL_FROM_U => Exception::EcallFromU,
            EXC_ECALL_FROM_S => Exception::EcallFromS,
            EXC_INSTRUCTION_PAGE_FAULT => Exception::InstructionPageFault,
            EXC_LOAD_PAGE_FAULT => Exception::LoadPageFault,
            EXC_STORE_PAGE_FAULT => Exception::StorePageFault,
            _ => Exception::Unknown(exc_num),
        };
        Trap::Exception(exc)
    }
}

/// arch/riscv64/trap/timer.rs
/// RISC-V S-mode 定时器 — CPU 核心中断机制
///
/// 硬件模型:
///   mtime    — 64 位递增计数器 (QEMU virt: 10 MHz)
///   mtimecmp — 比较寄存器, mtime >= mtimecmp 时触发 S-Timer 中断
///
/// SBI Timer 后端选择 (运行时探测):
///   1. SBI v0.2 Timer Extension (EID=0x54494D45, FID=0)
///      OpenSBI v0.7+ 及支持 SBI v0.2 规范的所有实现均支持。
///      能正确清除 sip.STIP, 在 OpenSBI+sstc 环境下唯一可靠方案。
///   2. Legacy set_timer (EID=0x0)
///      SBI v0.1 legacy 接口, 所有 SBI 实现均支持作为回退。
///      在 OpenSBI+sstc 环境下 STIP 清除行为不稳定, 避免主动选用。
///
/// 探测流程 (init 阶段一次性执行):
///   1. SBI Base Extension probe_extension(0x54494D45):
///      a0 = 0 (成功): a1 > 0 表示扩展可用
///      a0 != 0: 扩展不可用或探测失败, 一律回退 legacy
///   2. 若扩展可用, 用 v0.2 set_timer 编程短 deadline 并检查 sip.STIP,
///      只有确认中断 pending 能产生时才启用 v0.2 后端
///
/// 去耦合设计:
///   trap handler 调用 on_tick(can_preempt) → 重置下次中断 + 调用注册的回调
///   回调由 main.rs 在初始化阶段通过 register_tick_handler() 注册
///   arch 模块完全不知道 sched 模块的存在
use core::sync::atomic::{AtomicBool, AtomicU64, AtomicUsize, Ordering};

const SBI_EXT_BASE: u64 = 0x10;
const SBI_BASE_PROBE_EXTENSION: u64 = 3;
const SBI_EXT_TIME: u64 = 0x5449_4D45;
const SBI_SUCCESS: i64 = 0;
const SIE_STIE: usize = 1 << 5;
const SIP_STIP: usize = 1 << 5;

/// QEMU virt 的 mtime 频率: 10 MHz
const CLOCK_FREQ: u64 = 10_000_000;

/// 时钟中断间隔 (tick): 1ms = 10MHz × 0.001s = 10,000 ticks
const TICK_INTERVAL: u64 = CLOCK_FREQ / 1000; // 1000 Hz

// ─── SBI 后端选择 ──────────────────────────────────────────

/// true = 使用 SBI v0.2 Timer Extension (EID=0x54494D45)
/// false = 使用 legacy set_timer (EID=0x0)
static USE_TIMER_EXT: AtomicBool = AtomicBool::new(false);

/// 探测 SBI Timer Extension 并验证定时器中断 pending 能否产生。
///
/// SBI v0.2+ 规范: sbi_probe_extension 返回 a0=错误码, a1=探测结果。
///   a0=0, a1>0 → 扩展可用
///   a0!=0       → 扩展不可用, 回退 legacy
///
/// 仅检查 set_timer 返回值不够: RustSBI v0.2.2 可能返回成功但不产生后续 STIP。
/// 因此在 STIE 关闭时短暂 spin, 通过 sip.STIP 做一次中断活性验证。
fn detect_timer_backend() {
    let (error, extension_available) = sbi_probe_extension(SBI_EXT_TIME);
    let use_ext = error == SBI_SUCCESS
        && extension_available > 0
        && timer_v02_liveness_test();

    USE_TIMER_EXT.store(use_ext, Ordering::Relaxed);

    crate::kinfo!(
        "timer: {} backend (probe a0={}, a1={})",
        if use_ext { "v0.2 extension" } else { "legacy" },
        error,
        extension_available,
    );
}

fn sbi_probe_extension(extension_id: u64) -> (i64, i64) {
    let error: i64;
    let value: i64;
    unsafe {
        core::arch::asm!(
            "ecall",
            inlateout("a0") extension_id as i64 => error,
            lateout("a1") value,
            in("a6") SBI_BASE_PROBE_EXTENSION,
            in("a7") SBI_EXT_BASE,
            options(nostack),
        );
    }
    (error, value)
}

// ─── 回调机制 ─────────────────────────────────────────────

/// 已注册的回调函数指针 (0 = 无回调)
static TICK_HANDLER: AtomicUsize = AtomicUsize::new(0);

/// 注册定时器 tick 回调
///
/// 由 main.rs 在初始化阶段调用:
///   arch::trap::timer::register_tick_handler(sched::manager::timer_tick);
///
/// 这样 arch/ 只暴露注册接口, 不直接 import sched/ 的任何东西。
pub fn register_tick_handler(handler: fn(bool)) {
    TICK_HANDLER.store(handler as usize, Ordering::Relaxed);
}

/// 定时器中断处理入口 (由 trap handler 调用)
///
/// 1. 设置下一次中断
/// 2. 调用已注册的回调 (如果有)
pub fn on_tick(can_preempt: bool) {
    set_next_trigger();
    let ptr = TICK_HANDLER.load(Ordering::Relaxed);
    if ptr != 0 {
        let handler: fn(bool) = unsafe { core::mem::transmute(ptr) };
        handler(can_preempt);
    }
}

