/// 读取当前 mtime 值
///
/// RISC-V 允许 S-mode 使用 `rdtime` 伪指令 (实际读取 CSR time)。
#[inline(always)]
pub fn read_mtime() -> u64 {
    let val: u64;
    unsafe {
        core::arch::asm!("rdtime {}", out(reg) val, options(nostack, nomem));
    }
    val
}

fn timer_v02_liveness_test() -> bool {
    let old_stie = read_sie() & SIE_STIE != 0;
    disable_stie();

    // 先编程到较远未来，确认旧的 STIP pending 能被清掉，避免误判活性。
    let clear_deadline = read_mtime() + TICK_INTERVAL * 4;
    let ret = sbi_set_timer_v02_result(clear_deadline);
    if ret != SBI_SUCCESS {
        restore_stie(old_stie);
        return false;
    }

    let clear_stop = read_mtime() + TICK_INTERVAL;
    while timer_pending() && read_mtime() < clear_stop {
        core::hint::spin_loop();
    }
    if timer_pending() {
        restore_stie(old_stie);
        return false;
    }

    let deadline = read_mtime() + TICK_INTERVAL;
    let ret = sbi_set_timer_v02_result(deadline);
    if ret != SBI_SUCCESS {
        restore_stie(old_stie);
        return false;
    }

    let stop = deadline + TICK_INTERVAL;
    let mut pending = timer_pending();
    while !pending && read_mtime() < stop {
        core::hint::spin_loop();
        pending = timer_pending();
    }

    if pending {
        let cleanup_deadline = read_mtime() + TICK_INTERVAL * 4;
        let ret = sbi_set_timer_v02_result(cleanup_deadline);
        if ret != SBI_SUCCESS {
            restore_stie(old_stie);
            return false;
        }

        let cleanup_stop = read_mtime() + TICK_INTERVAL;
        while timer_pending() && read_mtime() < cleanup_stop {
            core::hint::spin_loop();
        }
        pending = !timer_pending();
    }

    restore_stie(old_stie);
    pending
}

fn read_sie() -> usize {
    let sie: usize;
    unsafe {
        core::arch::asm!("csrr {}, sie", out(reg) sie, options(nostack, nomem));
    }
    sie
}

fn disable_stie() {
    unsafe {
        core::arch::asm!("csrc sie, {stie}", stie = in(reg) SIE_STIE, options(nostack, nomem));
    }
}

fn restore_stie(was_enabled: bool) {
    if was_enabled {
        unsafe {
            core::arch::asm!("csrs sie, {stie}", stie = in(reg) SIE_STIE, options(nostack, nomem));
        }
    }
}

fn timer_pending() -> bool {
    let sip: usize;
    unsafe {
        core::arch::asm!("csrr {}, sip", out(reg) sip, options(nostack, nomem));
    }
    sip & SIP_STIP != 0
}

fn sbi_set_timer_v02_result(stime_value: u64) -> i64 {
    let error: u64;
    unsafe {
        core::arch::asm!(
            "ecall",
            inlateout("a0") stime_value => error,
            lateout("a1") _,
            in("a6") 0u64,
            in("a7") SBI_EXT_TIME,
            options(nostack),
        );
    }
    error as i64
}

