///
/// 适用于 OpenSBI v0.7+ 及所有兼容 SBI v0.2 规范的实现。
/// 能在 sstc 扩展激活时正确清除 sip.STIP。
#[inline(always)]
fn sbi_set_timer_v02(stime_value: u64) {
    let _ = sbi_set_timer_v02_result(stime_value);
}

/// 通过 SBI legacy set_timer 设置定时器 (EID=0x0)
///
/// SBI v0.1 接口，所有 SBI 实现均支持。
/// 在 OpenSBI+sstc 环境下 STIP 清除行为不稳定，仅作为回退使用。
#[inline(always)]
fn sbi_set_timer_legacy(stime_value: u64) {
    unsafe {
        core::arch::asm!(
            "ecall",
            inlateout("a0") stime_value => _,
            lateout("a1") _,
            in("a6") 0u64, // legacy 接口 a6 忽略，但保持寄存器干净
            in("a7") 0u64, // EID=0: legacy set_timer
            options(nostack),
        );
    }
}

/// 统一 SBI timer 调用入口，根据运行时探测结果分发
#[inline(always)]
fn sbi_set_timer(stime_value: u64) {
    if USE_TIMER_EXT.load(Ordering::Relaxed) {
        sbi_set_timer_v02(stime_value);
    } else {
        sbi_set_timer_legacy(stime_value);
    }
}

/// 当前已编程到 mtimecmp 的值，用于 set_one_shot 判断是否需要提前唤醒
static NEXT_MTIMECMP: AtomicU64 = AtomicU64::new(u64::MAX);

pub fn set_next_trigger() {
    let next = read_mtime() + TICK_INTERVAL;
    NEXT_MTIMECMP.store(next, Ordering::Relaxed);
    sbi_set_timer(next);
}

/// 将 mtimecmp 提前到 deadline（若 deadline 早于当前已编程值才更新）
///
/// 供 block_current_until() 调用，使 nanosleep 在精确时刻触发中断而非等待下一个 tick。
pub fn set_one_shot(deadline: u64) {
    let current = NEXT_MTIMECMP.load(Ordering::Relaxed);
    if deadline < current {
        NEXT_MTIMECMP.store(deadline, Ordering::Relaxed);
        sbi_set_timer(deadline);
    }
}

