/// arch/riscv64/trap/interrupt.rs — S-mode 中断开关
///
/// 提供 disable/restore 原语, 用于保护关键数据结构的原子操作。
///
/// 设计原则:
///   - 使用 save/restore 模式而非简单 on/off, 支持嵌套调用
///   - disable() 返回旧 SIE 位, restore() 接收该值决定是否重新开启
///   - 仅操作 sstatus.SIE (bit 1), 不影响其他 sstatus 位
///
/// 硬件机制 (RISC-V):
///   sstatus.SIE = 1 → 允许 S-mode 中断 (timer / external / software)
///   sstatus.SIE = 0 → 屏蔽所有 S-mode 中断
///   csrrc: 原子 "读旧值, 清指定位" — 单条指令完成读+改
///   csrs:  原子 "设置指定位"

/// 关闭 S-mode 中断, 返回之前的 SIE 状态
///
/// 用法:
/// ```
///   let guard = disable();
///   // ... 关键路径, 中断被屏蔽 ...
///   restore(guard);
/// ```
///
/// 返回值:
///   true  = 调用前中断是开启的 (SIE=1)
///   false = 调用前中断已关闭 (SIE=0, 嵌套场景)
#[inline(always)]
pub fn disable() -> bool {
    let old_sstatus: usize;
    unsafe {
        // csrrc: Read CSR, Clear bits specified by rs1
        // 读取 sstatus 旧值到 old_sstatus, 同时清除 bit 1 (SIE)
        core::arch::asm!(
            "csrrc {0}, sstatus, {1}",
            out(reg) old_sstatus,
            in(reg) 2usize,   // SIE 是 sstatus 的 bit 1
            options(nomem, nostack),
        );
    }
    // 旧值的 bit 1 就是之前的 SIE 状态
    (old_sstatus >> 1) & 1 != 0
}

/// 恢复 SIE 到 disable() 返回的状态
///
/// was_enabled = true  → 重新开启中断 (csrs sstatus, SIE)
/// was_enabled = false → 不操作 (保持关闭, 外层 guard 负责恢复)
#[inline(always)]
pub fn restore(was_enabled: bool) {
    if was_enabled {
        unsafe {
            core::arch::asm!(
                "csrs sstatus, {0}",
                in(reg) 2usize,   // 设置 SIE bit
                options(nomem, nostack),
            );
        }
    }
}

/// Query whether S-mode interrupts are currently disabled (SIE=0).
#[inline(always)]
pub fn is_disabled() -> bool {
    let sstatus: usize;
    unsafe {
        core::arch::asm!("csrr {}, sstatus", out(reg) sstatus, options(nomem, nostack));
    }
    (sstatus >> 1) & 1 == 0
}

/// 在关中断环境下执行闭包, 自动保存/恢复 SIE 状态
///
/// 替代手动 `let guard = disable(); ... restore(guard);` 模式。
/// 支持嵌套: 如果调用前中断已关闭, restore 不会意外开启。
///
/// 用法:
/// ```
///   let result = with_interrupts_disabled(|| {
///       unsafe { /* 访问全局可变状态 */ }
///   });
/// ```
///
/// 注意: 闭包内的 `return` 会从闭包返回 (不是从外层函数),
///       中断状态会被正确恢复。若需要从外层函数提前返回,
///       让闭包返回 Result/Option, 外层用 `?` 处理。
#[inline]
pub fn with_interrupts_disabled<F, R>(f: F) -> R
where
    F: FnOnce() -> R,
{
    let guard = disable();
    let result = f();
    restore(guard);
    result
}

/// src/mm/frame.rs
/// 物理页框管理
/// 负责管理物理内存中的页框（frame），提供分配和回收功能
/// 2026-03-09 -- Fwillra
use crate::hal::irq::with_interrupts_disabled;
use crate::mm::address::{PhysPageNum, PAGE_SIZE};

// ─── 常量 ─────────────────────────────────────────────────

/// 物理 RAM 起始地址（固定，RISC-V 平台规范）
const PHYS_BASE: usize = 0x8000_0000;
/// RAM 起始对应的绝对页号（用于绝对页号 ⇄ 位图索引转换）
const PHYS_BASE_PPN: usize = PHYS_BASE / PAGE_SIZE;

/// 运行时位图指针（init 后指向从可用内存高端切出的 metadata 区域）
static mut BITMAP_PTR: *mut u8 = core::ptr::null_mut();
/// 运行时引用计数指针
static mut REF_COUNT_PTR: *mut u16 = core::ptr::null_mut();
/// 运行时实际总页帧数（init 后设置）
static mut TOTAL_FRAMES: usize = 0;
/// 运行时实际内存顶端地址（init 后设置）
static mut MEMORY_END: usize = 0x8800_0000; // 默认 128MB fallback
/// 下次搜索起点提示（位图索引，加速连续分配）
static mut NEXT_HINT: usize = 0;

// ─── 对齐辅助函数 ─────────────────────────────────────────

#[inline]
fn align_up(addr: usize, align: usize) -> usize {
    (addr + align - 1) & !(align - 1)
}

#[inline]
fn align_down(addr: usize, align: usize) -> usize {
    addr & !(align - 1)
}

// ─── 位图底层操作 ─────────────────────────────────────────

/// 设置第 idx 位为 1（标记占用）
unsafe fn bitmap_set(idx: usize) {
    *BITMAP_PTR.add(idx / 8) |= 1 << (idx % 8);
}

/// 清除第 idx 位为 0（标记空闲）
unsafe fn bitmap_clear(idx: usize) {
    *BITMAP_PTR.add(idx / 8) &= !(1 << (idx % 8));
}

/// 测试第 idx 位是否为 1（是否占用）
unsafe fn bitmap_test(idx: usize) -> bool {
    *BITMAP_PTR.add(idx / 8) & (1 << (idx % 8)) != 0
}

/// 绝对页号 → 位图索引
#[inline]
fn ppn_to_index(ppn: PhysPageNum) -> (usize, usize) {
    let abs_ppn: usize = ppn.into();
    let idx = abs_ppn
        .checked_sub(PHYS_BASE_PPN)
        .expect("frame ppn below PHYS_BASE");
    (abs_ppn, idx)
}

// ─── 公开接口 ─────────────────────────────────────────────

/// 从 boot info 读取物理内存布局，运行时动态切出 bitmap / ref_count metadata。
///
/// 策略 "默认全占用，只释放 Usable"：
/// 1. 将所有帧标记为占用（bitmap 置全 1）
/// 2. 遍历所有 MemoryKind::Usable 区域，将对应帧清零
/// 3. 将 metadata 自身所在帧重新标记为占用
///
/// metadata 从可用的最大 Usable 区域高端切出。
pub fn init() {
    let boot_info = crate::hal::boot::info();

    // 1. 找到最高内存结束地址
    let mut memory_end = PHYS_BASE;
    for region in boot_info.memory_regions {
        let end: usize = region.end.into();
        if end > memory_end {
            memory_end = end;
        }
    }

    let total_frames = (memory_end - PHYS_BASE) / PAGE_SIZE;
    let bitmap_bytes = (total_frames + 7) / 8;
    let ref_count_bytes = total_frames * core::mem::size_of::<u16>();
    let meta_bytes = align_up(bitmap_bytes + ref_count_bytes, PAGE_SIZE);

    // 2. 找到最大的 Usable 区域，从高端切出 metadata
    let mut largest_start = 0usize;
    let mut largest_end = 0usize;
    let mut largest_size = 0usize;
    for region in boot_info.memory_regions {
        if region.kind == crate::hal::boot::MemoryKind::Usable {
            let start: usize = region.start.into();
            let end: usize = region.end.into();
            let size = end.saturating_sub(start);
            if size > largest_size {
                largest_start = start;
                largest_end = end;
                largest_size = size;
            }
        }
    }

    assert!(
        largest_size > meta_bytes,
        "Usable memory region too small for allocator metadata (need {} bytes, have {})",
        meta_bytes,
        largest_size
    );

    let meta_end_phys = align_down(largest_end, PAGE_SIZE);
    let meta_start_phys = meta_end_phys - meta_bytes;
    assert!(
        meta_start_phys >= largest_start,
        "Metadata carving exceeds usable region boundary"
    );

    unsafe {
        BITMAP_PTR = meta_start_phys as *mut u8;
        REF_COUNT_PTR = align_up(meta_start_phys + bitmap_bytes, core::mem::align_of::<u16>()) as *mut u16;
        TOTAL_FRAMES = total_frames;
        MEMORY_END = memory_end;
        NEXT_HINT = 0;

        // 3. 初始化 bitmap：默认全占用
        for i in 0..bitmap_bytes {
            *BITMAP_PTR.add(i) = 0xFF;
        }

        // 4. 释放所有 Usable 区域中的帧（按页边界对齐，避免释放部分保留页）
        for region in boot_info.memory_regions {
            if region.kind == crate::hal::boot::MemoryKind::Usable {
                let rstart: usize = region.start.into();
                let rend: usize = region.end.into();
                let start_aligned = align_up(rstart, PAGE_SIZE);
                let end_aligned = align_down(rend, PAGE_SIZE);
                if start_aligned < end_aligned {
                    let start_idx = (start_aligned - PHYS_BASE) / PAGE_SIZE;
                    let end_idx = ((end_aligned - PHYS_BASE) / PAGE_SIZE).min(total_frames);
                    for i in start_idx..end_idx {
                        bitmap_clear(i);
                    }
                }
            }
        }

        // 5. 将 metadata 自身所在帧重新标记为占用
        let meta_start_idx = (meta_start_phys - PHYS_BASE) / PAGE_SIZE;
        let meta_end_idx = (meta_end_phys - PHYS_BASE) / PAGE_SIZE;
        for i in meta_start_idx..meta_end_idx {
            bitmap_set(i);
        }

        // 6. 清零引用计数
        for i in 0..total_frames {
            *REF_COUNT_PTR.add(i) = 0;
        }

        // 统计可用帧数
        let mut avail = 0usize;
        for i in 0..total_frames {
            if !bitmap_test(i) {
                avail += 1;
            }
        }

        crate::kinfo!(
            "Frame allocator: {} total frames, {} available, metadata at {:#x}",
            total_frames,
            avail,
            meta_start_phys
        );
    }
}

/// 分配一个物理页帧，返回 None 表示内存耗尽
///
/// 搜索策略：从 NEXT_HINT 开始扫描，到尾部后回绕到开头，
/// 形成环形搜索，保证不遗漏任何空闲帧。
pub fn alloc_frame() -> Option<PhysPageNum> {
    with_interrupts_disabled(|| unsafe {
        let total = TOTAL_FRAMES;
        if total == 0 {
            return None;
        }
        // 第一轮：从 hint → 尾部
        for i in NEXT_HINT..total {
            if !bitmap_test(i) {
                bitmap_set(i);
                *REF_COUNT_PTR.add(i) = 1;
                NEXT_HINT = i + 1;
                return Some(PhysPageNum::from(i + PHYS_BASE_PPN));
            }
        }
        // 第二轮：从头部 → hint（回绕搜索）
        for i in 0..NEXT_HINT {
            if !bitmap_test(i) {
                bitmap_set(i);
                *REF_COUNT_PTR.add(i) = 1;
                NEXT_HINT = i + 1;
                return Some(PhysPageNum::from(i + PHYS_BASE_PPN));
            }
        }
        None
    })
}

/// 分配 n 个物理连续的页帧, 返回起始页号
///
/// 线性扫描位图寻找 n 个连续空闲帧。
/// 用于需要物理连续内存的场景 (如内核栈)。
pub fn alloc_contiguous_frames(n: usize) -> Option<PhysPageNum> {
    assert!(n > 0, "alloc_contiguous_frames: n must be > 0");
    with_interrupts_disabled(|| unsafe {
        let total = TOTAL_FRAMES;
        if total == 0 {
            return None;
        }
        let mut start = 0usize;
        while start + n <= total {
            let mut all_free = true;
            let mut first_used = 0;
            for j in 0..n {
                if bitmap_test(start + j) {
                    all_free = false;
                    first_used = start + j;
                    break;
                }
            }
            if all_free {
                for j in 0..n {
                    bitmap_set(start + j);
                    *REF_COUNT_PTR.add(start + j) = 1;
                }
                NEXT_HINT = start + n;
                return Some(PhysPageNum::from(start + PHYS_BASE_PPN));
            }
            start = first_used + 1;
        }
        None
    })
}

/// 查询某物理帧的引用计数（用于 mprotect COW 隔离）
pub fn frame_ref_count(ppn: PhysPageNum) -> u16 {
    let (_, idx) = ppn_to_index(ppn);
    with_interrupts_disabled(|| unsafe {
        if idx < TOTAL_FRAMES {
            *REF_COUNT_PTR.add(idx)
        } else {
            0
        }
    })
}

