/// fork 需要知道每帧的虚拟页号和权限才能在子进程重建映射。
#[derive(Copy, Clone)]
pub struct UserMapping {
    pub vpn: VirtPageNum,
    pub ppn: PhysPageNum,
    pub flags: PTEFlags,
}

// ─── 帧后备映射存储 ─────────────────────────────────────

/// 用物理帧存放 UserMapping 数组, 避免在栈上分配巨大内联数组
///
/// 每个物理帧 (4KB) 可存放 170 个 UserMapping (每个 24 字节)。
/// 按需增长: 初始 1 帧, 最多 MAX_STORE_FRAMES 帧 (510 映射)。
struct MappingStore {
    /// 后备存储帧
    frames: [PhysPageNum; MAX_STORE_FRAMES],
    /// 已分配帧数
    frame_count: usize,
    /// 已存放映射数
    count: usize,
}

impl MappingStore {
    /// 创建新的映射存储 (分配 1 帧)
    fn new() -> Self {
        let f = alloc_frame().expect("MappingStore: out of memory");
        let pa: usize = PhysAddr::from(f).into();
        unsafe {
            core::ptr::write_bytes(pa as *mut u8, 0, PAGE_SIZE);
        }
        Self {
            frames: {
                let mut arr = [PhysPageNum(0); MAX_STORE_FRAMES];
                arr[0] = f;
                arr
            },
            frame_count: 1,
            count: 0,
        }
    }

    /// 添加一个映射记录, 必要时自动扩展存储帧
    fn push(&mut self, m: UserMapping) {
        if self.count >= self.frame_count * MAPPINGS_PER_FRAME {
            assert!(
                self.frame_count < MAX_STORE_FRAMES,
                "MappingStore: overflow ({} mappings)",
                self.count
            );
            let f = alloc_frame().expect("MappingStore: out of memory for expansion");
            let pa: usize = PhysAddr::from(f).into();
            unsafe {
                core::ptr::write_bytes(pa as *mut u8, 0, PAGE_SIZE);
            }
            self.frames[self.frame_count] = f;
            self.frame_count += 1;
        }
        let fi = self.count / MAPPINGS_PER_FRAME;
        let li = self.count % MAPPINGS_PER_FRAME;
        let pa: usize = PhysAddr::from(self.frames[fi]).into();
        unsafe {
            (pa as *mut UserMapping).add(li).write(m);
        }
        self.count += 1;
    }

    /// 读取第 idx 个映射
    fn get(&self, idx: usize) -> UserMapping {
        debug_assert!(idx < self.count);
        let fi = idx / MAPPINGS_PER_FRAME;
        let li = idx % MAPPINGS_PER_FRAME;
        let pa: usize = PhysAddr::from(self.frames[fi]).into();
        unsafe { (pa as *const UserMapping).add(li).read() }
    }

    /// 覆写第 idx 个映射
    fn set(&mut self, idx: usize, m: UserMapping) {
        debug_assert!(idx < self.count);
        let fi = idx / MAPPINGS_PER_FRAME;
        let li = idx % MAPPINGS_PER_FRAME;
        let pa: usize = PhysAddr::from(self.frames[fi]).into();
        unsafe {
            (pa as *mut UserMapping).add(li).write(m);
        }
    }

    /// swap-remove: 用末尾元素替换 idx 处的元素, count -= 1
    fn swap_remove(&mut self, idx: usize) {
        debug_assert!(idx < self.count);
        self.count -= 1;
        if idx < self.count {
            let last = self.get(self.count);
            self.set(idx, last);
        }
    }

    fn len(&self) -> usize {
        self.count
    }
}

impl Drop for MappingStore {
    fn drop(&mut self) {
        for i in 0..self.frame_count {
            dealloc_frame(self.frames[i]);
        }
    }
}

/// 进程地址空间
///
/// 内部结构:
///   page_table ─── 独立页表 (L2 根表 + 中间页表页)
///                  创建时已 splice 内核映射
///   satp_val ───── 预计算的 satp 寄存器值
///   mappings ──── 帧后备存储, 记录所有用户页映射 (代码/数据/栈/堆)
///                  drop 时回收所有用户帧
pub struct AddressSpace {
    page_table: PageTable,
    satp_val: usize,
    /// 用户页映射记录 — 帧后备存储, 不占栈空间
    mappings: MappingStore,
    /// 虚拟内存区域列表 — 描述允许存在映射的地址范围
    areas: VmAreaList,
    /// 堆起始地址 (创建时固定)
    brk_start: usize,
    /// 当前 brk 地址 (sys_brk 调整)
    brk_current: usize,
    /// mmap 高水位线 — 下一次 addr=0 的 mmap 从此地址开始分配
    mmap_brk: usize,
    /// TLS (Thread Local Storage) 信息
    tls_info: crate::loader::tls::TlsInfo,
}

impl AddressSpace {
    /// 创建新地址空间
    ///
    /// 1. 分配新 PageTable (空根表)
    /// 2. 拼接内核映射 (RAM L2[2] + UART L2[0])
    /// 3. 预计算 satp 值
    /// 4. 分配映射存储帧 (1 帧, 按需扩展)
    pub fn new() -> Self {
        let mut page_table = PageTable::new();
        splice_kernel_mapping(&mut page_table);

        let root_ppn: usize = page_table.root_ppn().into();
        let satp_val = (SATP_SV39 << 60) | root_ppn;

        Self {
            page_table,
            satp_val,
            mappings: MappingStore::new(),
            areas: VmAreaList::new(),
            brk_start: DEFAULT_BRK_START,
            brk_current: DEFAULT_BRK_START,
            mmap_brk: DEFAULT_MMAP_BASE,
            tls_info: crate::loader::tls::TlsInfo::empty(),
        }
    }

    /// ELF 加载后初始化 brk: 设置堆起点为 ELF 数据段末尾的页对齐地址
    ///
    /// 必须在加载所有 PT_LOAD 段后、exec 返回前调用。
    /// max_load_end: 所有 PT_LOAD 段中 (vaddr + memsz) 的最大值
