        let brk = (max_load_end + PAGE_SIZE - 1) & !(PAGE_SIZE - 1);
        self.brk_start = brk;
        self.brk_current = brk;
    }

    /// 返回预计算的 satp 值
    pub fn satp(&self) -> usize {
        self.satp_val
    }

    /// 返回当前 brk 地址
    pub fn brk(&self) -> usize {
        self.brk_current
    }

    /// 设置新的 brk 地址 (延迟分配)
    ///
    /// 仅更新 brk_current 和 Heap VmArea 边界。
