/// mm/area.rs — 虚拟内存区域 (VmArea)
///
/// 描述进程地址空间中一段连续虚拟地址范围的属性。
/// 用于缺页处理: 判断 faulting address 是否属于合法 VmArea,
/// 若是则按需分配物理帧, 否则发送 SIGSEGV。
///
/// VmArea 不持有物理帧 — 物理帧由 MappingStore 跟踪。
/// VmArea 仅描述 "允许存在映射的虚拟地址范围和权限"。

use crate::mm::address::{PhysAddr, PhysPageNum, VirtPageNum, PAGE_SIZE};
use crate::mm::frame::{alloc_frame, dealloc_frame};
use crate::mm::pgtable::PTEFlags;

// ─── VmArea 定义 ─────────────────────────────────────────

/// 虚拟内存区域类型
///
/// 设计: MmapFile 只存 u8 索引, 避免枚举膨胀 (保持 VmArea ≤ 24 字节)
/// 文件映射的详细信息 (inode_idx, offset, shared) 存在全局 MMAP_FILE_TABLE
#[derive(Copy, Clone, Debug, PartialEq)]
#[repr(u8)]
pub enum VmAreaType {
    /// 匿名映射 (mmap MAP_ANONYMOUS)
    Anonymous = 0,
    /// 用户栈 (向下增长, 可自动扩展)
    Stack = 1,
    /// 堆区域 (brk, 向上增长)
    Heap = 2,
    /// ELF 代码/数据段
    Elf = 3,
    /// 文件映射 — 值为 MMAP_FILE_TABLE 的槽位索引
    MmapFile(u8) = 4,
}

// ─── MmapFile 全局查表 ─────────────────────────────────

/// 文件映射详细信息 (存在全局表中, 不内联到 VmAreaType)
#[derive(Copy, Clone)]
pub struct MmapFileInfo {
    pub used: bool,
    /// 文件系统 ID（MOUNT_TABLE 索引），绕过 VFS inode 生命周期
    pub fs_id: u8,
    /// 文件系统内部 inode 号
    pub fs_inode: u32,
    /// 文件大小（用于 EOF 截断判断）
    pub file_size: usize,
    /// 文件内偏移 (字节)
    pub offset: usize,
    /// MAP_SHARED 标志
    pub shared: bool,
}

const MMAP_FILE_SLOTS: usize = 64;

static mut MMAP_FILE_TABLE: [MmapFileInfo; MMAP_FILE_SLOTS] = [MmapFileInfo {
    used: false, fs_id: 0, fs_inode: 0, file_size: 0, offset: 0, shared: false,
}; MMAP_FILE_SLOTS];
static mut MMAP_FILE_REFS: [u16; MMAP_FILE_SLOTS] = [0; MMAP_FILE_SLOTS];

/// 分配一个 MmapFile 表槽位, 返回 slot index
pub fn mmap_file_alloc(
    fs_id: u8,
    fs_inode: u32,
    file_size: usize,
    offset: usize,
    shared: bool,
) -> Option<u8> {
    unsafe {
        for i in 0..MMAP_FILE_SLOTS {
            if !MMAP_FILE_TABLE[i].used {
                MMAP_FILE_TABLE[i] = MmapFileInfo {
                    used: true,
                    fs_id,
                    fs_inode,
                    file_size,
                    offset,
                    shared,
                };
                MMAP_FILE_REFS[i] = 1;
                return Some(i as u8);
            }
        }
        None
    }
}

/// 释放 MmapFile 表槽位
pub fn mmap_file_free(slot: u8) {
    unsafe {
        let s = slot as usize;
        if s < MMAP_FILE_SLOTS && MMAP_FILE_TABLE[s].used {
            if MMAP_FILE_REFS[s] > 1 {
                MMAP_FILE_REFS[s] -= 1;
                return;
            }
            MMAP_FILE_TABLE[s] = MmapFileInfo {
                used: false,
                fs_id: 0,
                fs_inode: 0,
                file_size: 0,
                offset: 0,
                shared: false,
            };
            MMAP_FILE_REFS[s] = 0;
        }
    }
}

/// 增加 MmapFile 表槽位引用计数（fork/拆分 VmArea 时使用）
pub fn mmap_file_retain(slot: u8) -> bool {
    unsafe {
        let s = slot as usize;
        if s < MMAP_FILE_SLOTS && MMAP_FILE_TABLE[s].used {
            MMAP_FILE_REFS[s] = MMAP_FILE_REFS[s].saturating_add(1);
            true
        } else {
            false
        }
    }
}

/// 查询 MmapFile 表槽位信息
pub fn mmap_file_get(slot: u8) -> Option<MmapFileInfo> {
    unsafe {
        let s = slot as usize;
        if s < MMAP_FILE_SLOTS && MMAP_FILE_TABLE[s].used {
            Some(MMAP_FILE_TABLE[s])
        } else {
            None
        }
    }
}

/// 为同一文件映射克隆一个带新偏移的槽位（VmArea 拆分右半段使用）
pub fn mmap_file_clone_with_delta(slot: u8, offset_delta: usize) -> Option<u8> {
    let info = mmap_file_get(slot)?;
    mmap_file_alloc(
        info.fs_id,
        info.fs_inode,
        info.file_size,
        info.offset.saturating_add(offset_delta),
        info.shared,
    )
}

/// 将当前 VmArea 持有的文件映射引用移动到新偏移（左侧被 munmap 时使用）
pub fn mmap_file_shift_ref(slot: u8, offset_delta: usize) -> Option<u8> {
    unsafe {
        let s = slot as usize;
        if s >= MMAP_FILE_SLOTS || !MMAP_FILE_TABLE[s].used {
            return None;
        }
        if offset_delta == 0 {
            return Some(slot);
        }

        let mut info = MMAP_FILE_TABLE[s];
        info.offset = info.offset.saturating_add(offset_delta);

        if MMAP_FILE_REFS[s] <= 1 {
            MMAP_FILE_TABLE[s] = info;
            return Some(slot);
        }

        for i in 0..MMAP_FILE_SLOTS {
            if !MMAP_FILE_TABLE[i].used {
                MMAP_FILE_TABLE[i] = info;
                MMAP_FILE_REFS[i] = 1;
                MMAP_FILE_REFS[s] -= 1;
                return Some(i as u8);
            }
        }
        None
    }
}

/// 一段连续虚拟地址范围的描述
///
/// [start_vpn, end_vpn) — 半开区间, end_vpn 不包含
#[derive(Copy, Clone)]
pub struct VmArea {
    /// 起始虚拟页号 (含)
    pub start_vpn: VirtPageNum,
    /// 结束虚拟页号 (不含)
    pub end_vpn: VirtPageNum,
    /// 页权限标志
    pub flags: PTEFlags,
    /// 区域类型
    pub area_type: VmAreaType,
}

impl VmArea {
    /// 检查给定虚拟页号是否在此区域内
    pub fn contains(&self, vpn: VirtPageNum) -> bool {
        vpn.0 >= self.start_vpn.0 && vpn.0 < self.end_vpn.0
    }

    /// 区域包含的页数
    #[allow(dead_code)]
    pub fn page_count(&self) -> usize {
        self.end_vpn.0 - self.start_vpn.0
    }
}

// ─── VmAreaList: 帧后备存储 ──────────────────────────────

/// 每帧可存放的 VmArea 数量
/// VmArea: 8 + 8 + 1 + 1 = 18 字节, 对齐到 24 字节 (同 UserMapping)
const AREAS_PER_FRAME: usize = PAGE_SIZE / core::mem::size_of::<VmArea>();

/// 最大存储帧数 (1 帧 ≈ 170 个 VmArea, 绰绰有余)
#[allow(dead_code)]
const MAX_AREA_FRAMES: usize = 1;

/// 用物理帧存放 VmArea 数组
///
/// 设计与 MappingStore 相同: 避免在栈/BSS 分配固定大小内联数组。
pub struct VmAreaList {
    frame: PhysPageNum,
    count: usize,
}

impl VmAreaList {
    /// 创建新的 VmArea 列表 (分配 1 帧)
    pub fn new() -> Self {
        let f = alloc_frame().expect("VmAreaList: out of memory");
        let pa: usize = PhysAddr::from(f).into();
        unsafe { core::ptr::write_bytes(pa as *mut u8, 0, PAGE_SIZE); }
        Self { frame: f, count: 0 }
    }

    /// 添加一个 VmArea
    pub fn push(&mut self, area: VmArea) {
        assert!(self.count < AREAS_PER_FRAME,
                "VmAreaList: overflow ({} areas)", self.count);
        let pa: usize = PhysAddr::from(self.frame).into();
        unsafe { (pa as *mut VmArea).add(self.count).write(area); }
        self.count += 1;
    }

    /// 读取第 idx 个 VmArea
    pub fn get(&self, idx: usize) -> VmArea {
        debug_assert!(idx < self.count);
        let pa: usize = PhysAddr::from(self.frame).into();
        unsafe { (pa as *const VmArea).add(idx).read() }
    }

    /// 覆写第 idx 个 VmArea
    pub fn set(&mut self, idx: usize, area: VmArea) {
        debug_assert!(idx < self.count);
        let pa: usize = PhysAddr::from(self.frame).into();
        unsafe { (pa as *mut VmArea).add(idx).write(area); }
    }

    /// swap-remove: 删除第 idx 个
    #[allow(dead_code)]
    pub fn swap_remove(&mut self, idx: usize) {
        debug_assert!(idx < self.count);
        self.count -= 1;
        if idx < self.count {
            let last = self.get(self.count);
            self.set(idx, last);
        }
    }

    /// 区域数量
    pub fn len(&self) -> usize {
        self.count
    }

    /// 查找包含给定 VPN 的 VmArea, 返回索引
    pub fn find(&self, vpn: VirtPageNum) -> Option<usize> {
        for i in 0..self.count {
            if self.get(i).contains(vpn) {
                return Some(i);
            }
        }
        None
    }

    /// 查找包含给定 VPN 的 VmArea, 返回副本
    pub fn find_area(&self, vpn: VirtPageNum) -> Option<VmArea> {
        self.find(vpn).map(|i| self.get(i))
    }
}

impl Drop for VmAreaList {
    fn drop(&mut self) {
        dealloc_frame(self.frame);
    }
}

/// src/sched/task.rs
/// 进程控制块（TCB）与任务切换上下文
///
/// TaskContext: 仅保存 callee-saved 寄存器 (ra, sp, s0-s11)，共 14×8=112 字节
/// TaskControlBlock: 进程的全部内核态元数据
/// TaskState: Ready / Running / Blocked / Exited 四状态生命周期
///
/// 设计要点:
/// - 零堆分配: TCB 存储在固定大小全局数组 TASKS[] 中
/// - RAII: PidHandle 保证 PID 自动回收
/// - 内核栈: 每进程 2 页 (8KB)，通过 alloc_contiguous_frames 保证连续

use crate::hal::context::TaskContext;
use crate::hal::trap::UserTrapFrame as TrapContext;
use crate::mm::address::{PhysAddr, PhysPageNum, PAGE_SIZE};
use crate::mm::address_space::AddressSpace;
use crate::mm::frame::{alloc_contiguous_frames, dealloc_frame};
use crate::sched::pid::{self, PidHandle};
use crate::sched::signal::SignalState;

#[derive(Copy, Clone)]
pub struct PosixTimerState {
    pub active: bool,
    pub signo: u32,
