    pub next_deadline: u64,
}

impl PosixTimerState {
    pub const fn new() -> Self {
        Self {
            active: false,
            signo: 0,
            interval_ticks: 0,
            next_deadline: 0,
        }
    }
}

// ─── 常量 ─────────────────────────────────────────────────

/// 每个进程的内核栈页数 (16 页 = 64KB)
const KERNEL_STACK_PAGES: usize = 16;

/// 最大进程数（与 pid.rs 的 MAX_PROCESSES 保持一致）
pub const MAX_TASKS: usize = 512;

/// 每进程文件描述符最大数量
pub const MAX_FDS: usize = 128;

/// 每进程最大子进程数量 (零堆分配, 固定数组)
pub const MAX_CHILDREN: usize = 512;

// ─── 文件描述符类型 ───────────────────────────────────────

/// 文件描述符类型 — 描述 fd 连接到什么设备
///
/// 每进程一张 fd 表 ([FdKind; MAX_FDS])，sys_read / sys_write
/// 通过查表分发到不同的后端实现。
///
/// Copy + Clone: 允许在固定大小数组中直接初始化, 零堆分配
#[derive(Copy, Clone, Debug)]
#[allow(dead_code)]
pub enum FdKind {
    /// 空槽位 (fd 未绑定)
    None,
    /// VFS 文件对象 (索引到 fs::FILE_TABLE)
    File(u16),
    /// 管道读端 (PipeId 为全局管道 ID)
    PipeRead(usize),
    /// 管道写端 (PipeId 为全局管道 ID)
    PipeWrite(usize),
    /// socketpair 端点 (持有一个读 pipe 和一个写 pipe)
    SocketEnd { read_pipe: usize, write_pipe: usize },
    /// timerfd 定时器对象 (全局槽位索引)
    TimerFd(u16),
}

// ─── 任务状态 ─────────────────────────────────────────────

/// 进程生命周期状态
///
///   UnInit → Ready ⇄ Running → Zombie → (回收)
///                ↕
///             Blocked
#[derive(Copy, Clone, Eq, PartialEq, Debug)]
#[allow(dead_code)]
pub enum TaskState {
    /// 槽位未使用
    UnInit,
    /// 就绪，等待调度
    Ready,
    /// 正在运行（全局同一时刻最多 1 个）
    Running,
    /// 阻塞（等待 I/O 或 IPC）
    Blocked,
    /// 已停止（如 SIGSTOP），等待 SIGCONT 恢复运行
    Stopped,
    /// 已退出，等待父进程 waitpid 回收
    /// TCB 槽位保留 exit_code, 但地址空间/内核栈已释放
    Zombie,
    /// 已退出，等待回收 (旧状态, 待 Zombie 完全替代后移除)
    Exited,
}

// ─── 内核栈操作 ───────────────────────────────────────────

/// 分配一个内核栈 (KERNEL_STACK_PAGES 个物理连续页)
///
/// 返回 (各页页号数组, 栈顶地址)
///
/// 使用 alloc_contiguous_frames 保证物理连续, 分配后清零。
pub(crate) fn alloc_kernel_stack() -> ([PhysPageNum; KERNEL_STACK_PAGES], usize) {
    let base_ppn = alloc_contiguous_frames(KERNEL_STACK_PAGES)
        .expect("alloc_kernel_stack: out of memory");
    let base_val: usize = base_ppn.into();
    let mut pages = [PhysPageNum::from(0usize); KERNEL_STACK_PAGES];
    for i in 0..KERNEL_STACK_PAGES {
        pages[i] = PhysPageNum::from(base_val + i);
        let pa: usize = PhysAddr::from(pages[i]).into();
        unsafe { core::ptr::write_bytes(pa as *mut u8, 0, PAGE_SIZE); }
    }
    let top_pa: usize = PhysAddr::from(pages[KERNEL_STACK_PAGES - 1]).into();
    let kstack_top = top_pa + PAGE_SIZE;
    (pages, kstack_top)
}

/// 释放内核栈 (逐页释放, 不假定连续)
pub(crate) fn dealloc_kernel_stack(pages: &[PhysPageNum; KERNEL_STACK_PAGES]) {
    for i in 0..KERNEL_STACK_PAGES {
        dealloc_frame(pages[i]);
    }
}

