/// 就绪队列容量
const QUEUE_CAP: usize = MAX_TASKS;

/// 全局任务管理器 (BSS 段, 单例)
pub(crate) static mut MANAGER: TaskManager = TaskManager::new();

/// 定时器信号投递暂存区。
///
/// 单核 + 关中断模型下不会并发访问；放在静态区避免 timer 扫描在被
/// S-mode 中断打断的任意内核栈上分配大数组。
static mut TIMER_PENDING_SIGNALS: [(usize, u32); MAX_TASKS] = [(0, 0); MAX_TASKS];

pub(crate) struct TaskManager {
    pub(crate) tasks: [Option<TaskControlBlock>; MAX_TASKS],
    pub(crate) ready_queue: [usize; QUEUE_CAP],
    pub(crate) queue_head: usize,
    pub(crate) queue_tail: usize,
    pub(crate) queue_count: usize,
    pub(crate) current: usize,
    pub(crate) idle_ctx: TaskContext,
    /// 废弃上下文 — exit_current 用 (退出任务不会恢复, 但 __switch 需要写入目标)
    pub(crate) scratch_ctx: TaskContext,
    /// 延迟回收: __switch 后需要 drop 的 orphan PID
    pub(crate) pending_reap: [usize; MAX_TASKS],
    pub(crate) pending_reap_count: usize,
    pub(crate) initialized: bool,
}

impl TaskManager {
    const fn new() -> Self {
        // const 初始化: 全零/None
        // 利用 const 表达式避免运行时开销
        const NONE_TCB: Option<TaskControlBlock> = None;
        Self {
            tasks: [NONE_TCB; MAX_TASKS],
            ready_queue: [0usize; QUEUE_CAP],
            queue_head: 0,
            queue_tail: 0,
            queue_count: 0,
            current: 0, // 初始 = idle
            idle_ctx: TaskContext::zero(),
            scratch_ctx: TaskContext::zero(),
            pending_reap: [0usize; MAX_TASKS],
            pending_reap_count: 0,
            initialized: false,
        }
    }

    /// 将 PID 加入就绪队列尾部
    pub(crate) fn queue_push(&mut self, pid: usize) {
        assert!(
            self.queue_count < QUEUE_CAP,
            "ready_queue: overflow (count={})",
            self.queue_count
        );
        self.ready_queue[self.queue_tail] = pid;
        self.queue_tail = (self.queue_tail + 1) % QUEUE_CAP;
        self.queue_count += 1;
    }

    /// 从就绪队列头部取出 PID, 空则返回 None
    pub(crate) fn queue_pop(&mut self) -> Option<usize> {
        if self.queue_count == 0 {
            return None;
        }
        let pid = self.ready_queue[self.queue_head];
        self.queue_head = (self.queue_head + 1) % QUEUE_CAP;
        self.queue_count -= 1;
        Some(pid)
    }

    /// 从就绪队列中取出下一个仍然可运行的任务
    pub(crate) fn pop_next_runnable(&mut self) -> usize {
        while let Some(pid) = self.queue_pop() {
            if pid == 0 {
                return 0;
            }
            if pid >= MAX_TASKS {
                continue;
            }
            match self.tasks[pid].as_ref() {
                Some(tcb) if tcb.state == TaskState::Ready => return pid,
                _ => continue,
            }
        }
        0
    }

    /// 将 Ready 任务放入就绪队列，并检查是否重复入队
    pub(crate) fn push_runnable(&mut self, pid: usize) {
        assert!(pid > 0 && pid < MAX_TASKS, "push_runnable: invalid pid {}", pid);
        let tcb = self.tasks[pid]
            .as_ref()
            .unwrap_or_else(|| panic!("push_runnable: missing task for pid {}", pid));
        assert!(
            tcb.state == TaskState::Ready,
            "push_runnable: pid {} state {:?} is not Ready",
            pid,
            tcb.state
        );
        for i in 0..self.queue_count {
            let idx = (self.queue_head + i) % QUEUE_CAP;
            assert!(
                self.ready_queue[idx] != pid,
                "push_runnable: pid {} already queued",
                pid
            );
        }
        self.queue_push(pid);
    }

    /// 创建任务并加入就绪队列
    ///
    /// entry: 任务入口函数地址
    /// 返回: 分配到的 PID, 或 None 表示资源不足
    fn spawn(&mut self, entry: usize) -> Option<usize> {
        let tcb = TaskControlBlock::new(entry)?; // 分配 PID + 内核栈 + 构造初始上下文
        let pid = tcb.pid_num(); // 获取分配到的 PID 编号
        assert!(
            pid > 0 && pid < MAX_TASKS, // PID 0 保留给 idle, 不能超出池大小
            "spawn: invalid pid {}",
            pid
        );
        assert!(
            self.tasks[pid].is_none(), // 槽位必须空闲 (防止 PID 重复)
            "spawn: slot {} already occupied",
            pid
        );
        self.tasks[pid] = Some(tcb); // 将 TCB 放入全局池的对应槽位
        let t = self.tasks[pid].as_mut().unwrap(); // 获取可变引用
        t.state = TaskState::Ready; // 设置状态为就绪
        t.time_slice = DEFAULT_TIME_SLICE; // 分配初始时间片
        self.push_runnable(pid); // 加入就绪队列尾部
        pid.into() // 返回 PID 编号
