pub fn clear_child_tid_and_wake(pid: usize, uaddr: usize) {
    let guard = crate::hal::irq::disable();
    unsafe {
        if pid == 0 || pid >= task::MAX_TASKS {
            crate::hal::irq::restore(guard);
            return;
        }
        let Some(tcb) = manager::MANAGER.tasks[pid].as_ref() else {
            crate::hal::irq::restore(guard);
            return;
        };
        let owner = tcb.addr_space_owner;
        let Some(owner_tcb) = manager::MANAGER.tasks[owner].as_mut() else {
            crate::hal::irq::restore(guard);
            return;
        };
        let Some(addr_space) = owner_tcb.addr_space.as_mut() else {
            crate::hal::irq::restore(guard);
            return;
        };
        let _ = crate::syscall::check::write_bytes_to_addr_space(
            addr_space,
            uaddr,
            &0u32.to_le_bytes(),
        );
    }
    crate::hal::irq::restore(guard);

    let _ = crate::syscall::futex_wake_addr(uaddr, 1);
}

