fn read_timespec_user(ptr: usize) -> Option<(i64, i64)> {
    if ptr == 0 {
        return None;
    }
    let mut bytes = [0u8; 16];
    super::check::read_bytes_from_user(ptr, &mut bytes).ok()?;
    let sec = i64::from_le_bytes(bytes[0..8].try_into().ok()?);
    let nsec = i64::from_le_bytes(bytes[8..16].try_into().ok()?);
    if sec < 0 || nsec < 0 || nsec >= 1_000_000_000 {
        return None;
    }
    Some((sec, nsec))
}

fn timespec_to_ticks(sec: i64, nsec: i64) -> u64 {
    sec as u64 * CLOCK_FREQ + (nsec as u64 * CLOCK_FREQ) / 1_000_000_000
}

fn read_timeval_user(ptr: usize) -> Option<(i64, i64)> {
    if ptr == 0 {
        return None;
    }
    let mut bytes = [0u8; 16];
    super::check::read_bytes_from_user(ptr, &mut bytes).ok()?;
    let sec = i64::from_le_bytes(bytes[0..8].try_into().ok()?);
    let usec = i64::from_le_bytes(bytes[8..16].try_into().ok()?);
    if sec < 0 || usec < 0 || usec >= 1_000_000 {
        return None;
    }
    Some((sec, usec))
}

fn timeval_to_ticks(sec: i64, usec: i64) -> u64 {
    sec as u64 * CLOCK_FREQ + (usec as u64 * CLOCK_FREQ) / 1_000_000
}

