pub fn sys_set_tid_address(args: [usize; 6]) -> isize {
    let tidptr = args[0];
    let pid = manager::current_pid();
    if pid == 0 {
        return -errno::ESRCH;
    }
    if tidptr != 0 {
        if let Err(err) = super::check::validate_user_buffer_write(tidptr, core::mem::size_of::<u32>()) {
            return err;
        }
    }
    let guard = crate::hal::irq::disable();
    unsafe {
        if let Some(tcb) = crate::sched::manager::MANAGER.tasks[pid].as_mut() {
            tcb.clear_child_tid = tidptr;
        }
    }
    crate::hal::irq::restore(guard);
    pid as isize
}

fn signalable_state(state: TaskState) -> bool {
    state != TaskState::UnInit && state != TaskState::Zombie && state != TaskState::Exited
}

fn task_slot_exists(pid: usize) -> bool {
    if pid == 0 || pid >= MAX_TASKS {
        return false;
    }
    let guard = crate::hal::irq::disable();
    let exists = unsafe { crate::sched::manager::MANAGER.tasks[pid].is_some() };
    crate::hal::irq::restore(guard);
    exists
}

fn current_process_group() -> Result<usize, isize> {
    let cur = manager::current_pid();
    if cur == 0 || cur >= MAX_TASKS {
        return Err(-errno::ESRCH);
    }
    let guard = crate::hal::irq::disable();
    let pgid = unsafe {
        crate::sched::manager::MANAGER.tasks[cur]
            .as_ref()
            .map(|tcb| tcb.pgid)
    };
    crate::hal::irq::restore(guard);
    pgid.ok_or(-errno::ESRCH)
}

