pub fn sys_setpgid(args: [usize; 6]) -> isize {
    let pid_arg = args[0];
    let pgid_arg = args[1];
    let cur = manager::current_pid();
    if cur == 0 || cur >= MAX_TASKS {
        return -errno::ESRCH;
    }

    let target = if pid_arg == 0 { cur } else { pid_arg };
    if target == 0 || target >= MAX_TASKS {
        return -errno::ESRCH;
    }
    let requested_pgid = if pgid_arg == 0 { target } else { pgid_arg };
    if requested_pgid == 0 {
        return -errno::EINVAL;
    }

    let guard = crate::hal::irq::disable();
    let ret = unsafe {
        let current_sid = crate::sched::manager::MANAGER.tasks[cur]
            .as_ref()
            .map(|tcb| tcb.sid);
        let target_info = crate::sched::manager::MANAGER.tasks[target]
            .as_ref()
            .map(|tcb| (tcb.state, tcb.parent_pid, tcb.sid));

        match (current_sid, target_info) {
            (Some(current_sid), Some((target_state, target_parent, target_sid))) => {
