                    -errno::EPERM
                } else if target_sid != current_sid {
                    -errno::EPERM
                } else {
                    let mut group_exists = requested_pgid == target;
                    if !group_exists && requested_pgid < MAX_TASKS {
                        for pid in 1..MAX_TASKS {
                            if let Some(tcb) = crate::sched::manager::MANAGER.tasks[pid].as_ref() {
                                if tcb.sid == current_sid && tcb.pgid == requested_pgid {
                                    group_exists = true;
                                    break;
                                }
                            }
                        }
