                    if !group_exists {
                        -errno::EPERM
                    } else {
                        match crate::sched::manager::MANAGER.tasks[target].as_mut() {
                            Some(tcb) => {
                                tcb.pgid = requested_pgid;
                                0
                            }
                            None => -errno::ESRCH,
                        }
                    }
                }
            }
            _ => -errno::ESRCH,
        }
    };
    crate::hal::irq::restore(guard);
    ret
}

