/// syscall/io.rs — I/O 类系统调用
///
/// 所有文件I/O通过VFS层分发:
///   FdKind::File(gfd) → fs::file_read/file_write
///   FdKind::PipeRead/PipeWrite → pipe 模块
///
/// fd 分发机制: 查询当前进程 TCB 的 fd_table,
/// 根据 FdKind 类型分发到不同后端。
use super::errno;
use crate::fs;
use crate::sched::manager;
use crate::sched::task::FdKind;

/// 单次 I/O 最大字节数 (防止长时间阻塞调度)
const IO_MAX: usize = 65536;

/// sys_write(fd, buf, len) → 写入的字节数 / 负错误码
pub fn sys_write(args: [usize; 6]) -> isize {
    let fd = args[0];
    let buf = args[1];
    let len = args[2];

    if len == 0 {
        return 0;
    }
    let len = if len > IO_MAX { IO_MAX } else { len };

    let kind = match manager::current_fd_kind(fd) {
        Some(k) => k,
        None => return -errno::EBADF,
    };

    match kind {
        FdKind::File(gfd) => {
            if let Err(e) = validate_user_buffer(buf, len) {
                return e;
            }
            let slice = unsafe { core::slice::from_raw_parts(buf as *const u8, len) };
            fs::file_write(gfd, slice)
        }
        FdKind::PipeWrite(pipe_id) => {
            if let Err(e) = validate_user_buffer(buf, len) {
                return e;
            }
            let slice = unsafe { core::slice::from_raw_parts(buf as *const u8, len) };
            crate::ipc::pipe::pipe_write_blocking(pipe_id, slice)
        }
        FdKind::SocketEnd { write_pipe, .. } => {
            if let Err(e) = validate_user_buffer(buf, len) {
                return e;
            }
            let slice = unsafe { core::slice::from_raw_parts(buf as *const u8, len) };
            crate::ipc::pipe::pipe_write_blocking(write_pipe, slice)
        }
        _ => -errno::EBADF,
    }
}

/// sys_read(fd, buf, len) → 读取的字节数 / 负错误码
pub fn sys_read(args: [usize; 6]) -> isize {
    let fd = args[0];
    let buf = args[1];
    let len = args[2];

    if len == 0 {
        return 0;
    }
    let len = if len > IO_MAX { IO_MAX } else { len };

    let kind = match manager::current_fd_kind(fd) {
        Some(k) => k,
        None => return -errno::EBADF,
    };

    match kind {
        FdKind::File(gfd) => {
            if let Err(e) = validate_user_buffer_write(buf, len) {
                return e;
            }
            let slice = unsafe { core::slice::from_raw_parts_mut(buf as *mut u8, len) };
            fs::file_read(gfd, slice)
        }
        FdKind::PipeRead(pipe_id) => {
            if let Err(e) = validate_user_buffer_write(buf, len) {
                return e;
            }
            let slice = unsafe { core::slice::from_raw_parts_mut(buf as *mut u8, len) };
            crate::ipc::pipe::pipe_read_blocking(pipe_id, slice)
        }
        FdKind::SocketEnd { read_pipe, .. } => {
            if let Err(e) = validate_user_buffer_write(buf, len) {
                return e;
            }
            let slice = unsafe { core::slice::from_raw_parts_mut(buf as *mut u8, len) };
            crate::ipc::pipe::pipe_read_blocking(read_pipe, slice)
        }
        _ => -errno::EBADF,
    }
}

