/// sys_pipe2(pipefd, flags) → 0 / 负错误码
pub fn sys_pipe2(args: [usize; 6]) -> isize {
    use crate::ipc::pipe;
    use crate::sched::task::FdKind;

    let pipefd_ptr = args[0];
    let flags = args[1];
    const O_CLOEXEC: usize = 0x80000;

    if let Err(e) = validate_user_buffer(pipefd_ptr, 8) {
        return e;
    }

    let pipe_id = match pipe::pipe_create() {
        Some(id) => id,
        None => return -errno::EMFILE,
    };

    let read_fd = match manager::alloc_fd(FdKind::PipeRead(pipe_id)) {
        Some(fd) => fd,
        None => {
            pipe::pipe_close_reader(pipe_id);
            pipe::pipe_close_writer(pipe_id);
            return -errno::EMFILE;
        }
    };

    let write_fd = match manager::alloc_fd(FdKind::PipeWrite(pipe_id)) {
        Some(fd) => fd,
        None => {
            manager::close_fd(read_fd);
            pipe::pipe_close_writer(pipe_id);
            return -errno::EMFILE;
        }
    };

    if flags & O_CLOEXEC != 0 {
        crate::sched::fd::set_fd_cloexec(read_fd, true);
        crate::sched::fd::set_fd_cloexec(write_fd, true);
    }

    let mut pipefd_bytes = [0u8; 8];
    pipefd_bytes[..4].copy_from_slice(&(read_fd as i32).to_le_bytes());
    pipefd_bytes[4..].copy_from_slice(&(write_fd as i32).to_le_bytes());
    match super::check::write_bytes_to_user(pipefd_ptr, &pipefd_bytes) {
        Ok(()) => {}
        Err(e) => {
            manager::close_fd(read_fd);
            manager::close_fd(write_fd);
            return e;
        }
    }

    0
}

