/// sys_dup3(oldfd, newfd, flags) → newfd / -errno
pub fn sys_dup3(args: [usize; 6]) -> isize {
    let oldfd = args[0];
    let newfd = args[1];
    let flags = args[2];
    const O_CLOEXEC: usize = 0x80000;
    if oldfd == newfd {
        return -errno::EINVAL;
    }
    let cloexec = flags & O_CLOEXEC != 0;
    match manager::dup3_fd(oldfd, newfd, cloexec) {
        Some(fd) => fd as isize,
        None => -errno::EBADF,
    }
}

