/// sys_ioctl(fd, request, arg) → 0 / -ENOTTY
///
/// busybox sh 用 ioctl(TIOCGWINSZ) 检测终端窗口大小,
/// isatty() 也通过 ioctl 判断。返回 -ENOTTY 表示非终端。
pub fn sys_ioctl(args: [usize; 6]) -> isize {
    let fd = args[0];
    let request = args[1] as u32;

    const TIOCGWINSZ: u32 = 0x5413;
    const TIOCSPGRP: u32 = 0x5410;
    const TIOCGPGRP: u32 = 0x540F;
    const TCGETS: u32 = 0x5401;
    const TCSETS: u32 = 0x5402;
    const RTC_RD_TIME: u32 = 0x80247009;

    match request {
        TIOCGWINSZ => {
            if fd <= 2 {
                crate::fs::devfs::devfs_ioctl(1, TIOCGWINSZ, args[2])
            } else {
                -errno::ENOTTY
            }
        }
        TCGETS | TCSETS | TIOCSPGRP | TIOCGPGRP => {
            if fd <= 2 {
                0
            } else {
                -errno::ENOTTY
            }
        }
        RTC_RD_TIME => {
            let kind = match manager::current_fd_kind(fd) {
                Some(k) => k,
                None => return -errno::EBADF,
            };
            let gfd = match kind {
                FdKind::File(g) => g,
                _ => return -errno::ENOTTY,
            };
            let inode_idx = match fs::file_inode_idx(gfd) {
                Some(idx) => idx,
                None => return -errno::EBADF,
            };
            let fs_id = fs::inode_fs_id(inode_idx);
            let fs_inode = fs::inode_fs_inode(inode_idx);
            if fs_id != crate::fs::MOUNT_DEVFS {
                return -errno::ENOTTY;
            }
            crate::fs::devfs::devfs_ioctl(fs_inode, RTC_RD_TIME, args[2])
        }
        _ => -errno::ENOTTY,
    }
}

