/// 通过全局 inode 索引读取数据 (供 mmap 缺页处理使用)
pub fn inode_read(inode_idx: u16, offset: usize, buf: &mut [u8]) -> isize {
    crate::hal::irq::with_interrupts_disabled(|| unsafe {
        let inode = &vfs::INODE_TABLE[inode_idx as usize];
        if inode.itype == InodeType::Free {
            return -5;
        }
        let ops = vfs::get_ops(inode.fs_id);
        (ops.read)(inode.fs_id, inode.fs_inode, offset, buf)
    })
}

