pub(super) fn get_ops(fs_id: u8) -> &'static FsOps {
    match fs_id {
        MOUNT_RAMFS => &RAMFS_OPS,
        MOUNT_DEVFS => &DEVFS_OPS,
        MOUNT_EXT4 => &EXT4_OPS,
        MOUNT_PROCFS => &PROCFS_OPS,
        MOUNT_SHM => &RAMFS_OPS,
        _ => unsafe {
            if (fs_id as usize) < MAX_MOUNTS {
                match MOUNT_TABLE[fs_id as usize].fs_type {
                    FsType::RamFs => &RAMFS_OPS,
                    FsType::DevFs => &DEVFS_OPS,
                    FsType::Ext4 => &EXT4_OPS,
                    FsType::ProcFs => &PROCFS_OPS,
                    FsType::None => panic!("get_ops: empty fs_id {}", fs_id),
                }
            } else {
                panic!("get_ops: unknown fs_id {}", fs_id)
            }
        },
    }
