// ─── VFS 初始化 ──────────────────────────────────────────

/// 初始化 VFS: 创建 ramfs 根目录, 挂载 devfs 到 /dev
pub fn init() {
    with_interrupts_disabled(|| unsafe {
        // 初始化 RamFs
        ramfs::init();

        // 挂载 RamFs 为根文件系统 (mount index 0)
        MOUNT_TABLE[MOUNT_RAMFS as usize] = MountEntry {
            fs_type: FsType::RamFs,
            root_inode: 0,
            mount_inode: 0,
            _lock: 0,
        };

        // 分配全局 inode 给根目录
        let root_idx = alloc_inode_locked(InodeType::Dir, MOUNT_RAMFS, 0);
        ROOT_INODE_IDX = root_idx;
        INODE_TABLE[root_idx as usize].nlink = 1;
        INODE_TABLE[root_idx as usize].mode = 0o755;

        // 初始化 DevFs
        devfs::init();

        // 挂载 DevFs (mount index 1)
        MOUNT_TABLE[MOUNT_DEVFS as usize] = MountEntry {
            fs_type: FsType::DevFs,
            root_inode: 0,
            mount_inode: 0,
            _lock: 0,
        };

        // 在 RamFs 根目录下创建 "dev" 目录
        let dev_fs_inode = ramfs::ramfs_create(MOUNT_RAMFS, 0, b"dev", InodeType::Dir);
        if let Some(dev_fsi) = dev_fs_inode {
            let dev_idx = alloc_inode_locked(InodeType::Dir, MOUNT_DEVFS, 0);
            INODE_TABLE[dev_idx as usize].nlink = 1;
            INODE_TABLE[dev_idx as usize].mode = 0o755;
            MOUNT_TABLE[MOUNT_DEVFS as usize].mount_inode = dev_idx;

            let dev_ramfs_idx = alloc_inode_locked(InodeType::Dir, MOUNT_RAMFS, dev_fsi);
            INODE_TABLE[dev_ramfs_idx as usize].nlink = 1;
            MOUNT_TABLE[MOUNT_DEVFS as usize].mount_inode = dev_ramfs_idx;
        }

        // 在 ramfs 根目录创建 "tmp" 目录
        if let Some(tmp_fsi) = ramfs::ramfs_create(MOUNT_RAMFS, 0, b"tmp", InodeType::Dir) {
            let tmp_idx = alloc_inode_locked(InodeType::Dir, MOUNT_RAMFS, tmp_fsi);
            INODE_TABLE[tmp_idx as usize].nlink = 1;
            INODE_TABLE[tmp_idx as usize].mode = 0o1777;
        }

        // 初始化 ProcFs 并挂载到 /proc
        procfs::init();
        MOUNT_TABLE[MOUNT_PROCFS as usize] = MountEntry {
            fs_type: FsType::ProcFs,
            root_inode: 0,
            mount_inode: 0,
            _lock: 0,
        };
        if let Some(proc_fsi) = ramfs::ramfs_create(MOUNT_RAMFS, 0, b"proc", InodeType::Dir) {
            let proc_ramfs_idx = alloc_inode_locked(InodeType::Dir, MOUNT_RAMFS, proc_fsi);
            INODE_TABLE[proc_ramfs_idx as usize].nlink = 1;
            INODE_TABLE[proc_ramfs_idx as usize].mode = 0o555;
            MOUNT_TABLE[MOUNT_PROCFS as usize].mount_inode = proc_ramfs_idx;
        }

        let shm_devfs_fsinode = devfs::dev_shm_fsinode();
        let shm_devfs_idx = get_or_alloc_inode_locked(InodeType::Dir, MOUNT_DEVFS, shm_devfs_fsinode);
        INODE_TABLE[shm_devfs_idx as usize].nlink = 2;
        INODE_TABLE[shm_devfs_idx as usize].mode = 0o1777;
        if let Some(shm_ramfs_fsi) = ramfs::ramfs_alloc_root_dir() {
            MOUNT_TABLE[MOUNT_SHM as usize] = MountEntry {
                fs_type: FsType::RamFs,
                root_inode: shm_ramfs_fsi,
                mount_inode: shm_devfs_idx,
                _lock: 0,
            };
        }

        VFS_INITIALIZED = true;
    });
    crate::kinfo!("initialized: ramfs root + devfs at /dev + procfs at /proc");
}

/// 挂载 EXT4 文件系统到 /mnt
///
/// 保持 ramfs 为根文件系统 (/dev, /tmp 不受影响),
/// EXT4 磁盘内容可通过 /mnt/ 路径访问。
pub fn mount_ext4() -> bool {
    if !ext4::is_available() {
        return false;
    }

    let result = with_interrupts_disabled(|| unsafe {
        // 在 ramfs 根目录下创建 "mnt" 目录 (如果不存在)
        let mnt_fsi = match ramfs::ramfs_lookup(MOUNT_RAMFS, 0, b"mnt") {
            Some(fsi) => fsi,
            None => match ramfs::ramfs_create(MOUNT_RAMFS, 0, b"mnt", InodeType::Dir) {
                Some(fsi) => fsi,
                None => {
                    crate::kwarn!("failed to create /mnt");
                    return false;
                }
            },
        };

        // 为 /mnt 分配全局 inode
        let mnt_idx = get_or_alloc_inode_locked(InodeType::Dir, MOUNT_RAMFS, mnt_fsi);
        INODE_TABLE[mnt_idx as usize].nlink = 1;
        INODE_TABLE[mnt_idx as usize].mode = 0o755;

        // 注册 EXT4 挂载条目: mount_inode = /mnt 的全局 inode
        MOUNT_TABLE[MOUNT_EXT4 as usize] = MountEntry {
            fs_type: FsType::Ext4,
            root_inode: ext4::EXT4_ROOT_INO,
            mount_inode: mnt_idx,
            _lock: 0,
        };

        true
    });
    if result {
        crate::kinfo!("ext4 mounted at /mnt");
    }
    result
}

