/// ELF 非连续页框缓冲区
///
/// 将分散的物理页框抽象为一个逻辑连续的字节序列。
/// load_elf_from_pages 使用此结构按偏移读取 ELF 数据。
pub struct ElfBuf<'a> {
    pub frames: &'a [PhysPageNum],
    pub len: usize,
}

impl<'a> ElfBuf<'a> {
    /// 从逻辑偏移处读取 n 字节到 dst
    pub fn read_at(&self, offset: usize, dst: &mut [u8]) -> usize {
        if offset >= self.len {
            return 0;
        }
        let available = self.len - offset;
        let to_copy = dst.len().min(available);
        let mut copied = 0;
        let mut off = offset;
        while copied < to_copy {
            let page_idx = off / PAGE_SIZE;
            let page_off = off % PAGE_SIZE;
            let chunk = (PAGE_SIZE - page_off).min(to_copy - copied);
            let pa: usize = PhysAddr::from(self.frames[page_idx]).into();
            unsafe {
                core::ptr::copy_nonoverlapping(
                    (pa + page_off) as *const u8,
                    dst.as_mut_ptr().add(copied),
                    chunk,
                );
            }
            copied += chunk;
            off += chunk;
        }
        copied
    }

    /// 获取指向逻辑偏移处的物理地址指针 (仅当数据在单页内时有效)
    ///
    /// 返回 None 如果请求的范围跨页或越界
    #[allow(dead_code)]
    pub fn ptr_at(&self, offset: usize, len: usize) -> Option<*const u8> {
        if offset + len > self.len {
            return None;
        }
        let page_idx = offset / PAGE_SIZE;
        let page_off = offset % PAGE_SIZE;
        if page_off + len > PAGE_SIZE {
            return None; // 跨页, 需要用 read_at
        }
        let pa: usize = PhysAddr::from(self.frames[page_idx]).into();
        Some((pa + page_off) as *const u8)
    }
}

