/// 从 VFS 读取文件到物理页框
///
/// 返回 (已分配页数, 已读取字节数), 或 -errno
pub unsafe fn read_file_to_pages(
    cwd: u16,
    path: &[u8],
    frames: &mut [PhysPageNum],
) -> Result<(usize, usize), isize> {
    let gfd = vfs_open(cwd, path, O_RDONLY, 0).map_err(|e| e)?;

    let stat = match file_stat(gfd) {
        Some(s) => s,
        None => {
            dec_file_ref(gfd);
            return Err(-crate::errno::EINVAL);
        }
    };
    let file_size = stat.st_size as usize;
    if file_size == 0 || file_size > MAX_ELF_SIZE {
        dec_file_ref(gfd);
        return Err(-crate::errno::EINVAL);
    }

    let n_pages = (file_size + PAGE_SIZE - 1) / PAGE_SIZE;
    if n_pages > frames.len() {
        dec_file_ref(gfd);
        return Err(-crate::errno::ENOMEM);
    }

    let mut alloc_count = 0usize;
    for i in 0..n_pages {
        match alloc_frame() {
            Some(ppn) => {
                frames[i] = ppn;
                alloc_count += 1;
            }
            None => {
                free_pages(frames, alloc_count);
                dec_file_ref(gfd);
                return Err(-crate::errno::ENOMEM);
            }
        }
    }

    let mut total_read = 0usize;
    for i in 0..n_pages {
        let pa: usize = PhysAddr::from(frames[i]).into();
        let to_read = PAGE_SIZE.min(file_size - total_read);
        let buf = core::slice::from_raw_parts_mut(pa as *mut u8, to_read);
        let n = file_read(gfd, buf);
        if n <= 0 {
            if total_read == 0 {
                free_pages(frames, alloc_count);
                dec_file_ref(gfd);
                return Err(-crate::errno::EINVAL);
            }
            break;
        }
        total_read += n as usize;
        if total_read >= file_size {
            break;
        }
    }
    dec_file_ref(gfd);

    Ok((alloc_count, total_read))
}

/// 释放物理页框
pub fn free_pages(frames: &[PhysPageNum], count: usize) {
    for i in 0..count {
        dealloc_frame(frames[i]);
    }
}

/// 向用户态新地址空间的虚拟地址写入数据
///
/// 通过页表翻译 VA → PA 后用物理地址写入 (未切换 satp, 使用恒等映射)
unsafe fn write_to_va(addr_space: &AddressSpace, va: usize, data: &[u8]) {
    let mut off = 0;
    while off < data.len() {
        let cur_va = va + off;
        let vpn = VirtPageNum::from(cur_va / PAGE_SIZE);
        let page_off = cur_va % PAGE_SIZE;
        let pte = addr_space
            .translate(vpn)
            .expect("write_to_va: unmapped page");
        let pa: usize = PhysAddr::from(pte.ppn()).into();
        let chunk = (PAGE_SIZE - page_off).min(data.len() - off);
        core::ptr::copy_nonoverlapping(data.as_ptr().add(off), (pa + page_off) as *mut u8, chunk);
        off += chunk;
    }
}

/// 向虚拟地址写入一个 usize 值 (小端序)
unsafe fn write_usize_to_va(addr_space: &AddressSpace, va: usize, val: usize) {
    write_to_va(addr_space, va, &val.to_le_bytes());
}

