// ─── 超级块解析 ──────────────────────────────────────────

pub fn init() -> bool {
    unsafe {
        if !virtio_blk::is_available() {
            return false;
        }

        let mut sb_buf = [0u8; 1024];
        if !disk_io::read_bytes(SUPERBLOCK_OFFSET, &mut sb_buf) {
            crate::kerror!("failed to read superblock");
            return false;
        }

        let magic = disk_io::u16_at(&sb_buf, 0x38);
        if magic != EXT4_SUPER_MAGIC {
            crate::kerror!(
                "bad magic: {:#06x} (expected {:#06x})",
                magic,
                EXT4_SUPER_MAGIC
            );
            return false;
        }

        let s_log_block_size = disk_io::u32_at(&sb_buf, 0x18);
        let block_size = 1024u32 << s_log_block_size;

        let inodes_per_group = disk_io::u32_at(&sb_buf, 0x28);
        let blocks_per_group = disk_io::u32_at(&sb_buf, 0x20);
        let first_data_block = disk_io::u32_at(&sb_buf, 0x14);
        let inodes_count = disk_io::u32_at(&sb_buf, 0x00);
        let blocks_count_lo = disk_io::u32_at(&sb_buf, 0x04);
        let blocks_count_hi = disk_io::u32_at(&sb_buf, 0x150);
        let blocks_count = blocks_count_lo as u64 | ((blocks_count_hi as u64) << 32);

        let free_blocks_lo = disk_io::u32_at(&sb_buf, 0x0C);
        let free_blocks_hi = disk_io::u32_at(&sb_buf, 0x154);
        let free_blocks_count = free_blocks_lo as u64 | ((free_blocks_hi as u64) << 32);
        let free_inodes_count = disk_io::u32_at(&sb_buf, 0x10);

        let inode_size = disk_io::u16_at(&sb_buf, 0x58);
        let feature_incompat = disk_io::u32_at(&sb_buf, 0x60);
        let _feature_ro_compat = disk_io::u32_at(&sb_buf, 0x64);

        let has_extents = feature_incompat & 0x40 != 0;
        if !has_extents {
            crate::kwarn!("extent feature not set, may fail on indirect blocks");
        }

        let is_64bit = feature_incompat & 0x80 != 0;
        let bg_desc_size = if is_64bit {
            let desc_size = disk_io::u16_at(&sb_buf, 0xFE);
            if desc_size >= 64 {
                desc_size
            } else {
                64
            }
        } else {
            32
        };

        let group_count = (inodes_count + inodes_per_group - 1) / inodes_per_group;
        let bgdt_block = if block_size == 1024 { 2 } else { 1 };

        EXT4 = Ext4Info {
            initialized: true,
            block_size,
            inodes_per_group,
            inode_size,
            blocks_count,
            first_data_block,
            blocks_per_group,
            group_count,
            bgdt_block,
            bg_desc_size,
            inodes_count,
            free_blocks_count,
            free_inodes_count,
        };

        crate::kinfo!(
            "mounted: block_size={}, inodes_per_group={}, inode_size={}, groups={}, blocks={}",
            block_size,
            inodes_per_group,
            inode_size,
            group_count,
            blocks_count
        );
        true
    }
}

