unsafe fn free_extent_blocks(i_block: &[u8; 60]) {
    let eh_magic = u16_at(i_block, 0);
    if eh_magic != EXT4_EXT_MAGIC {
        return;
    }
    let eh_entries = u16_at(i_block, 2) as usize;
    let eh_depth = u16_at(i_block, 6);
    if eh_depth != 0 {
        return;
    }

    for i in 0..eh_entries {
        let ent_off = 12 + i * 12;
        let ee_len = u16_at(i_block, ent_off + 4) as u64;
        let ee_start_hi = u16_at(i_block, ent_off + 6) as u64;
        let ee_start_lo = u32_at(i_block, ent_off + 8) as u64;
        let ee_start = ee_start_lo | (ee_start_hi << 32);

        for b in 0..ee_len {
            alloc::free_block(ee_start + b);
        }
    }
}

