                }
            };

            if chunk == bs && off_in_block == 0 {
                write_block(phys, &buf[written..written + chunk]);
            } else {
                let mut blk_buf = [0u8; 4096];
                read_block(phys, &mut blk_buf);
                blk_buf[off_in_block..off_in_block + chunk]
                    .copy_from_slice(&buf[written..written + chunk]);
                write_block(phys, &blk_buf);
            }

            written += chunk;
            pos += chunk;
        }

        if end as u64 > i_size {
            inode::update_inode_size(fs_inode, end as u64);
        }

        written as isize
    }
}

pub fn ext4_lookup(_fs_id: u8, dir_fs_inode: u32, name: &[u8]) -> Option<u32> {
    if name == b"." {
        return Some(dir_fs_inode);
    }
    if name == b".." {
        return unsafe { dir::dir_lookup(dir_fs_inode, b"..") };
    }
    let result = unsafe { dir::dir_lookup(dir_fs_inode, name) };
    if result.is_some() {
        return result;
    }
    if is_busybox_applet(name) {
        return busybox_inode_in(dir_fs_inode);
    }
    None
}

pub fn ext4_create(_fs_id: u8, dir_ino: u32, name: &[u8], itype: InodeType) -> Option<u32> {
    unsafe {
        let ino = alloc::alloc_inode()?;
        let is_dir = matches!(itype, InodeType::Dir);
        let mode: u16 = if is_dir {
            EXT4_S_IFDIR | 0o755
        } else {
            EXT4_S_IFREG | 0o644
        };

        if !inode::init_new_inode(ino, mode, is_dir) {
            return None;
        }

        if !dir::dir_add_entry(dir_ino, name, ino, itype) {
            return None;
        }

        if is_dir {
            let parent_nlink = inode::read_inode_nlink(dir_ino);
            inode::update_inode_nlink(dir_ino, parent_nlink + 1);

            let blk = alloc::alloc_block()?;
            let mut i_block = [0u8; 60];
            i_block[0] = 0x0A;
            i_block[1] = 0xF3;
            i_block[4] = 4;
            i_block[5] = 0;
            extent::extent_append(&mut i_block, 0, blk);
            inode::write_inode_iblock(ino, &i_block);

            let bs = EXT4.block_size as usize;
            let mut dir_blk = [0u8; 4096];
            let dot_rec_len = 12u16;
            dir_blk[0..4].copy_from_slice(&ino.to_le_bytes());
            dir_blk[4] = dot_rec_len as u8;
            dir_blk[5] = (dot_rec_len >> 8) as u8;
            dir_blk[6] = 1;
            dir_blk[7] = EXT4_FT_DIR;
            dir_blk[8] = b'.';
            let dotdot_rec_len = (bs - 12) as u16;
            dir_blk[12..16].copy_from_slice(&dir_ino.to_le_bytes());
            dir_blk[16] = dotdot_rec_len as u8;
            dir_blk[17] = (dotdot_rec_len >> 8) as u8;
            dir_blk[18] = 2;
            dir_blk[19] = EXT4_FT_DIR;
            dir_blk[20] = b'.';
            dir_blk[21] = b'.';

            write_block(blk, &dir_blk);
            inode::update_inode_size(ino, bs as u64);
        }

        Some(ino)
    }
}

pub fn ext4_unlink(_fs_id: u8, dir_ino: u32, name: &[u8]) -> isize {
    unsafe {
        let child_ino = match dir::dir_lookup(dir_ino, name) {
            Some(ino) => ino,
            None => return -2,
        };

        if !dir::dir_remove_entry(dir_ino, name) {
            return -5;
        }

        let nlink = inode::read_inode_nlink(child_ino);
        if nlink <= 1 {
            if let Some((_mode, _size, i_flags, i_block)) = inode::read_raw_inode(child_ino) {
                if i_flags & EXT4_EXTENTS_FL != 0 {
                    free_extent_blocks(&i_block);
                }
            }
            inode::update_inode_nlink(child_ino, 0);
            alloc::free_inode(child_ino);
        } else {
            inode::update_inode_nlink(child_ino, nlink - 1);
        }

        0
    }
}

