/// pipe/ — POSIX 管道实现
///
/// 环形缓冲区 + 阻塞/唤醒语义, 零堆分配全局管道池
mod blocking;

pub use blocking::{pipe_read_blocking, pipe_write_blocking};

use crate::hal::irq::with_interrupts_disabled;
use crate::sched::manager;

const PIPE_BUF_SIZE: usize = 4096;
const MAX_PIPES: usize = 1024;
const EPIPE: isize = 32;
/// 单根管道最多同时阻塞的写者数量（hackbench 每组 40 tasks，保守取 64）
const MAX_BLOCKED_WRITERS: usize = 64;
/// 单根管道最多同时阻塞的读者数量
const MAX_BLOCKED_READERS: usize = 8;

struct Pipe {
    buf: [u8; PIPE_BUF_SIZE],
    read_pos: usize,
    write_pos: usize,
    count: usize,
    readers: usize,
    writers: usize,
    /// 阻塞读者 PID 队列（与写者侧对称）
    blocked_readers: [usize; MAX_BLOCKED_READERS],
    blocked_reader_count: usize,
    /// 阻塞写者 PID 队列（FIFO，0 表示空槽）
    blocked_writers: [usize; MAX_BLOCKED_WRITERS],
    blocked_writer_count: usize,
    active: bool,
}

impl Pipe {
    const fn new() -> Self {
        Self {
            buf: [0u8; PIPE_BUF_SIZE],
            read_pos: 0,
            write_pos: 0,
            count: 0,
            readers: 0,
            writers: 0,
            blocked_readers: [0usize; MAX_BLOCKED_READERS],
            blocked_reader_count: 0,
            blocked_writers: [0usize; MAX_BLOCKED_WRITERS],
            blocked_writer_count: 0,
            active: false,
        }
    }
}

static mut PIPES: [Pipe; MAX_PIPES] = {
    const INIT: Pipe = Pipe::new();
    [INIT; MAX_PIPES]
};

enum ReadAction {
    Block,
    Yield,
    Return { result: isize, wake_pid: usize },
}
enum WriteAction {
    Block,
    Continue { wake_pid: usize },
    Return(isize),
}

pub fn pipe_create() -> Option<usize> {
    with_interrupts_disabled(|| unsafe {
        let mut found = None;
        for i in 0..MAX_PIPES {
            if !PIPES[i].active {
                PIPES[i] = Pipe::new();
                PIPES[i].active = true;
                PIPES[i].readers = 1;
                PIPES[i].writers = 1;
                found = Some(i);
                break;
            }
        }
        found
    })
}

pub fn pipe_write(pipe_id: usize, data: &[u8]) -> isize {
    let (result, wake_pid) = with_interrupts_disabled(|| unsafe {
        if pipe_id >= MAX_PIPES || !PIPES[pipe_id].active {
            return (-9, 0);
        }

        let p = &mut PIPES[pipe_id];
        if p.readers == 0 {
            return (-EPIPE, 0);
        }

        let space = PIPE_BUF_SIZE - p.count;
        let to_write = data.len().min(space);
        if to_write == 0 {
            return (0, 0);
        }

        for i in 0..to_write {
            p.buf[p.write_pos] = data[i];
            p.write_pos = (p.write_pos + 1) % PIPE_BUF_SIZE;
        }
        p.count += to_write;

        let wake_pid = if p.blocked_reader_count > 0 {
            let pid = p.blocked_readers[p.blocked_reader_count - 1];
            p.blocked_reader_count -= 1;
            pid
        } else {
            0
        };

        (to_write as isize, wake_pid)
    });
    if wake_pid != 0 {
        manager::wakeup(wake_pid);
    }
    result
}

pub fn pipe_read(pipe_id: usize, buf: &mut [u8]) -> isize {
    let mut wake_pids = [0usize; MAX_BLOCKED_WRITERS];
    let mut wake_count = 0usize;

    let result = with_interrupts_disabled(|| unsafe {
        if pipe_id >= MAX_PIPES || !PIPES[pipe_id].active {
            return (-9, 0);
        }

        let p = &mut PIPES[pipe_id];
        if p.count == 0 {
            return (0, 0);
        }

        let to_read = buf.len().min(p.count);
        for i in 0..to_read {
            buf[i] = p.buf[p.read_pos];
            p.read_pos = (p.read_pos + 1) % PIPE_BUF_SIZE;
        }
        p.count -= to_read;

        // Drain all blocked writers into local array so we can wake them outside.
        for i in 0..p.blocked_writer_count {
            wake_pids[i] = p.blocked_writers[i];
        }
        wake_count = p.blocked_writer_count;
        p.blocked_writer_count = 0;

        (to_read as isize, 0usize)
    });
    for i in 0..wake_count {
        manager::wakeup(wake_pids[i]);
    }
    result.0
}

pub fn pipe_close_writer(pipe_id: usize) {
    let mut wake_pids = [0usize; MAX_BLOCKED_READERS];
    let mut wake_count = 0usize;

    with_interrupts_disabled(|| unsafe {
        if pipe_id >= MAX_PIPES || !PIPES[pipe_id].active {
            return;
        }
        let p = &mut PIPES[pipe_id];
        if p.writers > 0 {
            p.writers -= 1;
        }
        // 最后一个写端关闭时，唤醒所有阻塞的读者（它们会收到 EOF）
        if p.writers == 0 {
            for i in 0..p.blocked_reader_count {
                wake_pids[i] = p.blocked_readers[i];
            }
            wake_count = p.blocked_reader_count;
            p.blocked_reader_count = 0;
        }
        if p.readers == 0 && p.writers == 0 {
            p.active = false;
        }
    });
    for i in 0..wake_count {
        manager::wakeup(wake_pids[i]);
    }
}

pub fn pipe_close_reader(pipe_id: usize) {
    let mut wake_pids = [0usize; MAX_BLOCKED_WRITERS];
    let mut wake_count = 0usize;

    with_interrupts_disabled(|| unsafe {
        if pipe_id >= MAX_PIPES || !PIPES[pipe_id].active {
            return;
        }
        let p = &mut PIPES[pipe_id];
        if p.readers > 0 {
            p.readers -= 1;
        }
        if p.readers == 0 {
            for i in 0..p.blocked_writer_count {
                wake_pids[i] = p.blocked_writers[i];
            }
            wake_count = p.blocked_writer_count;
            p.blocked_writer_count = 0;
        }
        let r = p.readers;
        let w = p.writers;
        if r == 0 && w == 0 {
            p.active = false;
        }
    });
    for i in 0..wake_count {
        manager::wakeup(wake_pids[i]);
    }
}

#[allow(dead_code)]
pub fn inc_readers(pipe_id: usize) {
    with_interrupts_disabled(|| unsafe {
        if pipe_id < MAX_PIPES && PIPES[pipe_id].active {
            PIPES[pipe_id].readers += 1;
        }
    });
}

#[allow(dead_code)]
pub fn inc_writers(pipe_id: usize) {
    with_interrupts_disabled(|| unsafe {
        if pipe_id < MAX_PIPES && PIPES[pipe_id].active {
            PIPES[pipe_id].writers += 1;
        }
    });
}

pub fn pipe_poll(pipe_id: usize, is_read_end: bool) -> u16 {
    with_interrupts_disabled(|| unsafe {
        if pipe_id >= MAX_PIPES || !PIPES[pipe_id].active {
            return 0x0020; // POLLNVAL
        }
        let p = &PIPES[pipe_id];
        let mut revents: u16 = 0;
        if is_read_end {
            if p.count > 0 {
                revents |= 0x0001; // POLLIN
            }
            if p.writers == 0 {
                revents |= 0x0010; // POLLHUP
                if p.count > 0 {
                    revents |= 0x0001; // POLLIN (data still available)
                }
            }
        } else {
            if p.count < PIPE_BUF_SIZE {
                revents |= 0x0004; // POLLOUT
            }
            if p.readers == 0 {
                revents |= 0x0008; // POLLERR (broken pipe)
            }
        }
        revents
    })
}

pub fn available_pipes() -> usize {
    with_interrupts_disabled(|| unsafe {
        let mut n = 0;
        for i in 0..MAX_PIPES {
            if !PIPES[i].active {
                n += 1;
            }
        }
        n
    })
}

/// sched/signal.rs — POSIX 信号子系统
///
/// 提供:
/// - 标准信号常量 (1-64)
/// - 信号默认动作定义
/// - SigAction 结构体 (与 Linux rt_sigaction 兼容)
/// - 每进程 SignalState (pending/blocked/handlers)
/// - 信号投递逻辑 (SIG_DFL / SIG_IGN / 用户处理函数)

use crate::hal::trap::FaultKind as ArchFaultKind;
use crate::hal::trap::{TrapCause, UserTrapFrame as Context};

// ─── 信号常量 (Linux RISC-V ABI) ──────────────────────────

pub const SIGHUP:    u32 = 1;
pub const SIGINT:    u32 = 2;
pub const SIGQUIT:   u32 = 3;
pub const SIGILL:    u32 = 4;
pub const SIGTRAP:   u32 = 5;
pub const SIGABRT:   u32 = 6;
pub const SIGBUS:    u32 = 7;
pub const SIGFPE:    u32 = 8;
pub const SIGKILL:   u32 = 9;
pub const SIGUSR1:   u32 = 10;
pub const SIGSEGV:   u32 = 11;
pub const SIGUSR2:   u32 = 12;
pub const SIGPIPE:   u32 = 13;
pub const SIGALRM:   u32 = 14;
pub const SIGTERM:   u32 = 15;
// 16 = unused on Linux
pub const SIGCHLD:   u32 = 17;
pub const SIGCONT:   u32 = 18;
pub const SIGSTOP:   u32 = 19;
pub const SIGTSTP:   u32 = 20;
pub const SIGTTIN:   u32 = 21;
pub const SIGTTOU:   u32 = 22;
pub const SIGURG:    u32 = 23;
pub const SIGXCPU:   u32 = 24;
pub const SIGXFSZ:   u32 = 25;
pub const SIGVTALRM: u32 = 26;
pub const SIGPROF:   u32 = 27;
pub const SIGWINCH:  u32 = 28;
pub const SIGIO:     u32 = 29;
pub const SIGPWR:    u32 = 30;
pub const SIGSYS:    u32 = 31;

/// 第一条非法信号编号 (1..=63 为有效信号；bit 64 无法放入 u64 位图)
pub const NSIG: u32 = 64;

// ─── U-mode 异常处理 (由 arch trap 回调调用) ──────────────

/// 处理 U-mode 异常: 将硬件异常映射到 POSIX 信号并发送给当前进程
///
/// 对于 PageFault, 先尝试按需分配 (demand paging):
///   - 若 faulting address 属于某个 VmArea → 分配帧并映射 → 静默返回
///   - 若不属于任何 VmArea → 发送 SIGSEGV
///
/// 此函数由 arch::trap::handler 通过回调调用, 实现 arch → sched 解耦。
pub fn handle_user_fault(sepc: usize, stval: usize, kind: ArchFaultKind) {
    let kind = match kind {
        ArchFaultKind::IllegalInstruction => TrapCause::IllegalInstruction,
        ArchFaultKind::PageFault => TrapCause::PageFault {
            addr: stval,
            write: false,
        },
        ArchFaultKind::WritePageFault => TrapCause::PageFault {
            addr: stval,
            write: true,
        },
        ArchFaultKind::AccessFault => TrapCause::Unknown(0),
        ArchFaultKind::Misaligned => TrapCause::Unknown(1),
    };

    // PageFault / WritePageFault: 尝试 demand paging / COW
    if let TrapCause::PageFault { write: is_write, .. } = kind {
        let handled = super::manager::with_current_addr_space(|addr_space| {
            crate::mm::fault::handle_page_fault(addr_space, stval, is_write)
        });
        if handled == Some(true) {
            return; // 已按需分配, 返回用户态重试
        }
    }

    let sig = match kind {
        TrapCause::IllegalInstruction => SIGILL,
        TrapCause::PageFault { .. } => SIGSEGV,
        TrapCause::Unknown(_) => SIGBUS,
        _ => SIGBUS,
    };
    let kind_str = match kind {
        TrapCause::IllegalInstruction => "ILL",
        TrapCause::PageFault { write: false, .. } => "PF",
        TrapCause::PageFault { write: true, .. } => "WPF",
        TrapCause::Unknown(0) => "AF",
        TrapCause::Unknown(1) => "MA",
        _ => "UNK",
    };
    let user_sp = super::manager::with_current_tcb(|tcb| {
        let ctx_size = core::mem::size_of::<Context>();
        let trap_ctx_addr = tcb.kstack_top - ctx_size;
        let trap_ctx = unsafe { &*(trap_ctx_addr as *const Context) };
        trap_ctx.as_arch().x[2]
    }).unwrap_or(0);
    crate::kwarn!("user fault → SIGSEGV: pid={} sepc={:#x} stval={:#x} sp={:#x} kind={}", super::manager::current_pid(), sepc, stval, user_sp, kind_str);
    super::manager::send_signal(super::manager::current_pid(), sig);
}

/// SIG_DFL: 默认动作
pub const SIG_DFL: usize = 0;
/// SIG_IGN: 忽略信号
pub const SIG_IGN: usize = 1;

/// SA_RESTORER: sigaction.restorer 有效
#[allow(dead_code)]
pub const SA_RESTORER: u32 = 0x04000000;
/// SA_SIGINFO: 使用 3 参数处理函数 (signum, siginfo, ucontext)
#[allow(dead_code)]
pub const SA_SIGINFO: u32 = 0x00000004;

// ─── 信号默认动作 ─────────────────────────────────────────

#[derive(Copy, Clone, PartialEq)]
pub enum DefaultAction {
    Terminate,
    CoreDump,  // 微内核不生成 core, 等同 Terminate
    Ignore,
    Stop,
    Continue,
}

/// 获取信号的默认动作 (POSIX 标准)
pub fn default_action(sig: u32) -> DefaultAction {
    match sig {
        SIGHUP  | SIGINT  | SIGPIPE | SIGALRM | SIGTERM |
        SIGUSR1 | SIGUSR2 | SIGPWR  | SIGIO   | SIGVTALRM |
        SIGPROF | SIGXCPU | SIGXFSZ => DefaultAction::Terminate,

        SIGQUIT | SIGILL  | SIGTRAP | SIGABRT | SIGBUS |
        SIGFPE  | SIGSEGV | SIGSYS  => DefaultAction::CoreDump,

        SIGCHLD | SIGURG  | SIGWINCH => DefaultAction::Ignore,

        SIGSTOP | SIGTSTP | SIGTTIN | SIGTTOU => DefaultAction::Stop,

        SIGCONT => DefaultAction::Continue,

        // SIGKILL(9) 特殊: 强制终止, 不可捕获/忽略
        SIGKILL => DefaultAction::Terminate,

        _ => DefaultAction::Terminate,
    }
}

// ─── SigAction 结构体 ────────────────────────────────────

/// 信号处理动作 (与 Linux struct kernel_sigaction 兼容)
#[derive(Copy, Clone)]
#[repr(C)]
pub struct SigAction {
    /// 处理函数: SIG_DFL(0), SIG_IGN(1), 或用户函数地址
    pub handler: usize,
    /// 标志位 (SA_SIGINFO, SA_RESTORER, 等)
    pub flags: u32,
    /// sigreturn 蹦床地址 (SA_RESTORER 时有效)
    pub restorer: usize,
    /// 处理器执行期间额外屏蔽的信号集
    pub mask: u64,
}

impl SigAction {
    pub const fn default() -> Self {
        SigAction {
            handler: SIG_DFL,
            flags: 0,
            restorer: 0,
            mask: 0,
        }
    }
}

// ─── 每进程信号状态 ──────────────────────────────────────

/// 每进程信号状态
pub struct SignalState {
    /// 待处理信号位图 (bit N = 信号 N 待处理)
    pub pending: u64,
    /// 被屏蔽的信号位图 (bit N = 信号 N 被阻塞)
    pub blocked: u64,
    /// 信号动作表 (索引 0 未使用, 1-63 对应标准信号)
    pub actions: [SigAction; NSIG as usize],
}

impl SignalState {
    pub const fn new() -> Self {
        SignalState {
            pending: 0,
            blocked: 0,
            actions: [SigAction::default(); NSIG as usize],
        }
    }

    /// fork 时克隆信号状态: 继承 blocked 和 SIG_IGN handlers, 其余重置为 SIG_DFL, 清除 pending
    ///
    /// POSIX 要求: fork 后子进程继承父进程信号处置, 但用户态 handler 地址在子进程
    /// 执行 exec 前仍然有效 (COW 共享物理页), 会导致子进程误触发父进程的 longjmp/
    /// sigcatcher 逻辑。Linux 内核的 do_fork 也会在 exec 时 reset, 但我们选择在
    /// fork 时就将非 SIG_IGN handler 重置为 SIG_DFL, 以符合 "子进程应尽快 exec"
    /// 的语义, 并阻断信号链式传播 (hackbench sigcatcher 级联问题)。
    pub fn fork_clone(&self) -> Self {
        let mut new_actions = self.actions;
        for i in 1..(NSIG as usize) {
            if new_actions[i].handler != SIG_IGN {
                new_actions[i] = SigAction::default(); // 重置为 SIG_DFL
            }
        }
        SignalState {
            pending: 0,
            blocked: self.blocked,
            actions: new_actions,
        }
    }

    /// 是否存在会打断阻塞 syscall 的 pending 信号。
    /// 用户 handler 需要返回 -EINTR；默认终止信号需要尽快返回 trap 路径完成投递。
    pub fn has_interrupting_pending(&self) -> bool {
        let deliverable = self.pending & !self.blocked;
