/// 内核入口点 - 由 boot/ 中的启动代码调用
#[no_mangle]
pub extern "C" fn kernel_main(hart_id: usize, dtb_pa: usize) -> ! {

    // ── 第一步: 初始化串口 + TTY 后端 ──
    // 必须在任何 print!/println!/kinfo! 之前完成,
    // 否则 TTY putc 走 no-op 路径, 丢失输出。
    arch::uart::init();
    tty::register_backend(tty::TtyBackend {
        putc: arch::uart::uart_putc,
        getc: arch::uart::try_getc,
    });

    // 打印欢迎信息 (此时 TTY 后端已就绪)
    println!("========================================");
    println!("  OSKernel v0.1.0");
    println!("  A UNIX-like Microkernel");
    println!("========================================");
    println!();
    println!("Hello, World from Rust Kernel!");
    println!();
    kinfo!("UART + TTY initialized");
    kinfo!("Architecture: RISC-V 64");

    unsafe {
        hal::boot::init(hart_id, dtb_pa);
    }

    let boot_info = hal::boot::info();
    kinfo!("CPUs detected: {}", boot_info.cpu_count);

    // 初始化中断功能
    arch::trap::init();
    kinfo!("TRAP initialized");

    // 注册 trap 回调: 将 syscall/信号处理注入到 arch 层
    // 这样 arch/ 完全不依赖 sched/ 或 syscall/, 只通过函数指针通信
    arch::trap::handler::register_trap_callbacks(arch::trap::handler::TrapCallbacks {
        syscall_dispatch: syscall::dispatch,
        pre_return_to_user: sched::manager::deliver_pending_signals,
        user_fault: sched::signal::handle_user_fault,
    });

    mm::frame::init();
    kinfo!("Frame allocator initialized");

    // 建立恒等映射并激活 MMU
    arch::mmu::paging::init();

    // 初始化 PLIC + 启用 UART 接收中断
    arch::plic::init();
    arch::uart::UART.enable_rx_interrupt();

    // 初始化 PID 分配器
    sched::pid::init();
    kinfo!("PID allocator initialized");

    // 初始化 VFS (在 task manager 之前, 因为 new_user 需要打开 /dev/console)
    fs::init();

    // 探测 Virtio 块设备 (在 VFS 之后, 后续可挂载磁盘)
    drivers::virtio_blk::probe();

    // 尝试挂载 EXT4 文件系统
    if drivers::virtio_blk::is_available() {
        if fs::ext4::init() {
            fs::mount_ext4();
        }
    }

    // 注册 fd 资源回调: 解耦 sched/ 对 ipc::pipe / fs 的直接依赖
    sched::fd::register_fd_callbacks(sched::fd::FdCallbacks {
        close: |kind| match kind {
            sched::task::FdKind::PipeRead(id) => ipc::pipe::pipe_close_reader(id),
            sched::task::FdKind::PipeWrite(id) => ipc::pipe::pipe_close_writer(id),
            sched::task::FdKind::File(gfd) => fs::dec_file_ref(gfd),
            sched::task::FdKind::SocketEnd { read_pipe, write_pipe } => {
                ipc::pipe::pipe_close_reader(read_pipe);
                ipc::pipe::pipe_close_writer(write_pipe);
            }
            _ => {}
        },
        clone_ref: |kind| match kind {
            sched::task::FdKind::PipeRead(id) => ipc::pipe::inc_readers(id),
            sched::task::FdKind::PipeWrite(id) => ipc::pipe::inc_writers(id),
            sched::task::FdKind::File(gfd) => fs::inc_file_ref(gfd),
            sched::task::FdKind::SocketEnd { read_pipe, write_pipe } => {
                ipc::pipe::inc_readers(read_pipe);
                ipc::pipe::inc_writers(write_pipe);
            }
            _ => {}
        },
    });

    // 初始化任务管理器
    sched::manager::init();

    // 注册定时器回调
    arch::trap::timer::register_tick_handler(sched::manager::timer_tick);

    // 初始化定时器 (启用 S-mode 时钟中断)
    arch::trap::timer::init();

    // ── 全面健全性测试 ──
    // test::sanity_tests();

    kinfo!("Kernel started successfully!");

    // ── 如果有磁盘, 启动 init 进程 ──
    if drivers::virtio_blk::is_available() {
        boot_init();
    } else {
        kinfo!("No disk attached — skipping init, auto shutdown");
        auto_shutdown();
    }
}

/// 内嵌 init 用户程序 ELF
static INIT_ELF: &[u8] = include_bytes!("../../user/build/init");

/// 将 init ELF 写入 ramfs, 加载并 spawn 为 PID 1, 然后进入调度循环
fn boot_init() -> ! {
    let root = fs::root_inode_idx();

    // 1. 写入 ramfs: 创建 /init
    let gfd = fs::vfs_open(root, b"/init\0", fs::O_CREAT | fs::O_WRONLY, 0o755)
        .expect("boot_init: cannot create /init in ramfs");
    let written = fs::file_write(gfd, INIT_ELF);
    fs::dec_file_ref(gfd);
    kinfo!("Wrote /init to ramfs ({} bytes)", written);

    // 2. 加载 ELF → 得到入口点和用户栈
    let info = loader::load_elf(INIT_ELF, &[b"/init" as &[u8]], &[])
        .expect("boot_init: load_elf failed");

    // 3. spawn 为用户进程 (PID 1)
    let pid = sched::manager::spawn_user(info.entry, info.user_sp, Some(info.addr_space));
    kinfo!("Spawned init process PID {}", pid);

    // 4. idle 循环: 让调度器接管
    loop {
        sched::manager::yield_current();
        hal::cpu::wfi();
    }
}

/// 无磁盘模式: 倒计时后关机
fn auto_shutdown() -> ! {
    println!();
    let start = hal::time::read_ticks();
    let freq = hal::time::ticks_per_second();
    for remaining in (1..=5).rev() {
        kinfo!("Auto shutdown in {} seconds...", remaining);
        let target = start + (6 - remaining) as u64 * freq;
        while hal::time::read_ticks() < target {
            hal::cpu::wfi();
        }
    }
    kinfo!("Shutting down via SBI...");
    hal::firmware::shutdown();
}

/// Panic 处理函数
#[panic_handler]
fn panic(info: &PanicInfo) -> ! {
    println!();
    println!("!!! KERNEL PANIC !!!");
    println!("{}", info);
    // panic后无限死循环
    // loop {
    //     arch::halt();
    // }
    // panic后自动关机
    auto_shutdown();
}

/// ext4/extent.rs — Extent 树遍历与追加
use super::disk_io::{read_block, u16_at, u32_at, BLOCK_BUF};
use super::{EXT4, EXT4_EXT_MAGIC};

/// 通过 extent 树将逻辑块号映射到物理块号
///
/// 支持 depth=0 (叶子 extent) 和 depth>0 (索引节点)
pub(crate) unsafe fn extent_map_block(i_block: &[u8; 60], logical_block: u64) -> Option<u64> {
    debug_assert!(
        crate::hal::irq::is_disabled(),
        "extent_map_block: BLOCK_BUF requires interrupts disabled"
    );
    let eh_magic = u16_at(i_block, 0);
    if eh_magic != EXT4_EXT_MAGIC {
        return None;
    }
    let eh_entries = u16_at(i_block, 2) as usize;
    let eh_depth = u16_at(i_block, 6);

    if eh_depth == 0 {
        return extent_leaf_lookup(i_block, 12, eh_entries, logical_block);
    }

    extent_index_lookup(i_block, 12, eh_entries, eh_depth, logical_block)
}

/// 在叶子 extent 数组中查找逻辑块
unsafe fn extent_leaf_lookup(
    buf: &[u8],
    offset: usize,
    entries: usize,
    logical_block: u64,
) -> Option<u64> {
    for i in 0..entries {
        let ent_off = offset + i * 12;
        if ent_off + 12 > buf.len() {
            break;
        }
        let ee_block = u32_at(buf, ent_off) as u64;
        let ee_len = u16_at(buf, ent_off + 4) as u64;
        let ee_start_hi = u16_at(buf, ent_off + 6) as u64;
        let ee_start_lo = u32_at(buf, ent_off + 8) as u64;
        let ee_start = ee_start_lo | (ee_start_hi << 32);

        if logical_block >= ee_block && logical_block < ee_block + ee_len {
            return Some(ee_start + (logical_block - ee_block));
        }
    }
    None
}

/// 在索引节点中查找, 递归读取子树
unsafe fn extent_index_lookup(
    buf: &[u8],
    offset: usize,
    entries: usize,
    depth: u16,
    logical_block: u64,
) -> Option<u64> {
    let mut best_idx: Option<usize> = None;
    for i in 0..entries {
        let ent_off = offset + i * 12;
        if ent_off + 12 > buf.len() {
            break;
        }
        let ei_block = u32_at(buf, ent_off) as u64;
        if ei_block <= logical_block {
            best_idx = Some(i);
        } else {
            break;
        }
    }

    let idx = best_idx?;
    let ent_off = offset + idx * 12;
    let ei_leaf_lo = u32_at(buf, ent_off + 4) as u64;
    let ei_leaf_hi = u16_at(buf, ent_off + 8) as u64;
    let child_block = ei_leaf_lo | (ei_leaf_hi << 32);

    if !read_block(child_block, &mut BLOCK_BUF) {
        return None;
    }

    let ch_magic = u16_at(&BLOCK_BUF, 0);
    if ch_magic != EXT4_EXT_MAGIC {
        return None;
    }
    let ch_entries = u16_at(&BLOCK_BUF, 2) as usize;
    let ch_depth = u16_at(&BLOCK_BUF, 6);

    if ch_depth == 0 {
        let mut leaf_buf = [0u8; 4096];
        leaf_buf[..EXT4.block_size as usize]
            .copy_from_slice(&BLOCK_BUF[..EXT4.block_size as usize]);
        return extent_leaf_lookup(&leaf_buf, 12, ch_entries, logical_block);
    }

    if depth <= 1 {
        return None;
    }
    let mut idx_buf = [0u8; 4096];
    idx_buf[..EXT4.block_size as usize].copy_from_slice(&BLOCK_BUF[..EXT4.block_size as usize]);
    extent_index_lookup(&idx_buf, 12, ch_entries, ch_depth, logical_block)
}

// ─── Extent 追加 (depth=0 only) ─────────────────────────

/// 在 extent 树中追加一个 logical→physical 块映射
///
/// 仅支持 depth=0 (叶子节点, 小文件足够):
///   - 如果最后一个 extent 与新块物理连续, 增加 ee_len
///   - 否则新增一个 extent entry (如果还有空间)
///
/// i_block: inode 的 60 字节 extent 树根 (会被修改)
/// 返回 true = 成功
pub(crate) unsafe fn extent_append(
    i_block: &mut [u8; 60],
    logical_block: u64,
    phys_block: u64,
) -> bool {
    debug_assert!(
        crate::hal::irq::is_disabled(),
        "extent_append: BLOCK_BUF requires interrupts disabled"
    );
    let eh_magic = u16_at(i_block, 0);
    if eh_magic != EXT4_EXT_MAGIC {
        return false;
    }
    let eh_entries = u16_at(i_block, 2) as usize;
    let eh_max = u16_at(i_block, 4) as usize;
    let eh_depth = u16_at(i_block, 6);

    // 只支持 depth=0
    if eh_depth != 0 {
        return false;
    }

    // 尝试扩展最后一个 extent
    if eh_entries > 0 {
        let last_off = 12 + (eh_entries - 1) * 12;
        let ee_block = u32_at(i_block, last_off) as u64;
        let ee_len = u16_at(i_block, last_off + 4) as u64;
        let ee_start_hi = u16_at(i_block, last_off + 6) as u64;
        let ee_start_lo = u32_at(i_block, last_off + 8) as u64;
        let ee_start = ee_start_lo | (ee_start_hi << 32);

        // 检查是否连续
        if logical_block == ee_block + ee_len && phys_block == ee_start + ee_len && ee_len < 32768
        // 最大 extent 长度
        {
            // 扩展: ee_len += 1
            let new_len = (ee_len + 1) as u16;
            let le = new_len.to_le_bytes();
            i_block[last_off + 4] = le[0];
            i_block[last_off + 5] = le[1];
            return true;
        }
    }

    // 新增 extent entry
    if eh_entries >= eh_max {
        return false; // 没空间了
    }

    let new_off = 12 + eh_entries * 12;
    // ee_block
    let lb = (logical_block as u32).to_le_bytes();
    i_block[new_off..new_off + 4].copy_from_slice(&lb);
    // ee_len = 1
    i_block[new_off + 4] = 1;
    i_block[new_off + 5] = 0;
    // ee_start_hi
    let shi = ((phys_block >> 32) as u16).to_le_bytes();
    i_block[new_off + 6] = shi[0];
    i_block[new_off + 7] = shi[1];
    // ee_start_lo
    let slo = (phys_block as u32).to_le_bytes();
    i_block[new_off + 8..new_off + 12].copy_from_slice(&slo);

    // eh_entries += 1
    let new_entries = (eh_entries + 1) as u16;
    let le = new_entries.to_le_bytes();
    i_block[2] = le[0];
    i_block[3] = le[1];

    true
}

/// ext4/alloc.rs — 块和 inode 分配器
///
/// 操作块组描述符中的 block bitmap / inode bitmap:
///   alloc_block() — 分配一个数据块
///   alloc_inode() — 分配一个 inode
///   free_block()  — 释放一个数据块
///
/// 分配策略: 从 group 0 开始线性扫描 bitmap, 找到第一个空闲位
use super::disk_io::{read_block, read_bytes, u16_at, u32_at, write_block, write_bytes};
use super::EXT4;

/// 从块组描述符读取 bitmap/inode_table 位置等信息
struct BgInfo {
    block_bitmap_block: u64,
    inode_bitmap_block: u64,
    free_blocks_lo: u16,
    free_inodes_lo: u16,
}

/// 读取指定块组的描述符信息
unsafe fn read_bg_info(group: u32) -> Option<BgInfo> {
    let bgdt_byte_offset =
        EXT4.bgdt_block as u64 * EXT4.block_size as u64 + group as u64 * EXT4.bg_desc_size as u64;

    let mut bg_buf = [0u8; 64];
    let read_len = if EXT4.bg_desc_size > 64 {
        64
    } else {
        EXT4.bg_desc_size as usize
    };
    if !read_bytes(bgdt_byte_offset, &mut bg_buf[..read_len]) {
        return None;
    }

    let block_bitmap_lo = u32_at(&bg_buf, 0x00) as u64;
    let inode_bitmap_lo = u32_at(&bg_buf, 0x04) as u64;
    let block_bitmap_hi = if EXT4.bg_desc_size >= 64 {
        u32_at(&bg_buf, 0x20) as u64
    } else {
        0
    };
    let inode_bitmap_hi = if EXT4.bg_desc_size >= 64 {
        u32_at(&bg_buf, 0x24) as u64
    } else {
        0
    };

    Some(BgInfo {
        block_bitmap_block: block_bitmap_lo | (block_bitmap_hi << 32),
        inode_bitmap_block: inode_bitmap_lo | (inode_bitmap_hi << 32),
        free_blocks_lo: u16_at(&bg_buf, 0x0C),
        free_inodes_lo: u16_at(&bg_buf, 0x0E),
    })
}

/// 更新块组描述符的 free_blocks_count_lo
unsafe fn update_bg_free_blocks(group: u32, new_count: u16) {
    let bgdt_byte_offset =
        EXT4.bgdt_block as u64 * EXT4.block_size as u64 + group as u64 * EXT4.bg_desc_size as u64;
    let buf = new_count.to_le_bytes();
    write_bytes(bgdt_byte_offset + 0x0C, &buf);
}

/// 更新块组描述符的 free_inodes_count_lo
unsafe fn update_bg_free_inodes(group: u32, new_count: u16) {
    let bgdt_byte_offset =
        EXT4.bgdt_block as u64 * EXT4.block_size as u64 + group as u64 * EXT4.bg_desc_size as u64;
    let buf = new_count.to_le_bytes();
    write_bytes(bgdt_byte_offset + 0x0E, &buf);
}

/// 分配一个数据块, 返回全局块号
///
/// 扫描所有块组的 block bitmap, 找到第一个空闲位
pub(crate) unsafe fn alloc_block() -> Option<u64> {
    let bs = EXT4.block_size as usize;

    for group in 0..EXT4.group_count {
        let bg = read_bg_info(group)?;
        if bg.free_blocks_lo == 0 {
            continue;
        }

        // 读 block bitmap (1 block 大小)
        let mut bitmap = [0u8; 4096];
        if !read_block(bg.block_bitmap_block, &mut bitmap) {
            continue;
        }

        // 扫描 bitmap 找空闲位
        let max_bits = EXT4.blocks_per_group as usize;
        for byte_idx in 0..bs.min((max_bits + 7) / 8) {
            if bitmap[byte_idx] == 0xFF {
                continue; // 全满
            }
            for bit_idx in 0..8u32 {
                let bit_pos = byte_idx * 8 + bit_idx as usize;
                if bit_pos >= max_bits {
                    break;
                }
                if bitmap[byte_idx] & (1 << bit_idx) == 0 {
                    // 空闲位! 置 1
                    bitmap[byte_idx] |= 1 << bit_idx;
                    write_block(bg.block_bitmap_block, &bitmap);

                    // 更新 free_blocks_count
                    if bg.free_blocks_lo > 0 {
                        update_bg_free_blocks(group, bg.free_blocks_lo - 1);
                    }

                    // 计算全局块号
                    let block_no = group as u64 * EXT4.blocks_per_group as u64
                        + EXT4.first_data_block as u64
                        + bit_pos as u64;
                    return Some(block_no);
                }
            }
        }
    }
    None
}

/// 分配一个 inode, 返回 inode 号
pub(crate) unsafe fn alloc_inode() -> Option<u32> {
    let bs = EXT4.block_size as usize;

    for group in 0..EXT4.group_count {
        let bg = read_bg_info(group)?;
        if bg.free_inodes_lo == 0 {
            continue;
        }

        let mut bitmap = [0u8; 4096];
        if !read_block(bg.inode_bitmap_block, &mut bitmap) {
            continue;
        }

        let max_bits = EXT4.inodes_per_group as usize;
        for byte_idx in 0..bs.min((max_bits + 7) / 8) {
            if bitmap[byte_idx] == 0xFF {
                continue;
            }
            for bit_idx in 0..8u32 {
                let bit_pos = byte_idx * 8 + bit_idx as usize;
                if bit_pos >= max_bits {
                    break;
                }
                if bitmap[byte_idx] & (1 << bit_idx) == 0 {
                    bitmap[byte_idx] |= 1 << bit_idx;
                    write_block(bg.inode_bitmap_block, &bitmap);

                    if bg.free_inodes_lo > 0 {
                        update_bg_free_inodes(group, bg.free_inodes_lo - 1);
                    }

                    // inode 号 = group * inodes_per_group + bit_pos + 1
                    let ino = group * EXT4.inodes_per_group + bit_pos as u32 + 1;
                    return Some(ino);
                }
            }
        }
    }
    None
}

/// 释放一个 inode
pub(crate) unsafe fn free_inode(ino: u32) {
    if ino == 0 {
        return;
    }
    let group = (ino - 1) / EXT4.inodes_per_group;
    let bit_pos = ((ino - 1) % EXT4.inodes_per_group) as usize;

    if group >= EXT4.group_count {
        return;
    }

    if let Some(bg) = read_bg_info(group) {
        let mut bitmap = [0u8; 4096];
        if read_block(bg.inode_bitmap_block, &mut bitmap) {
            let byte_idx = bit_pos / 8;
            let bit_idx = (bit_pos % 8) as u32;
            bitmap[byte_idx] &= !(1 << bit_idx);
            write_block(bg.inode_bitmap_block, &bitmap);
            update_bg_free_inodes(group, bg.free_inodes_lo + 1);
        }
    }
}

/// 释放一个数据块
pub(crate) unsafe fn free_block(block_no: u64) {
    let relative = block_no - EXT4.first_data_block as u64;
    let group = (relative / EXT4.blocks_per_group as u64) as u32;
    let bit_pos = (relative % EXT4.blocks_per_group as u64) as usize;

    if group >= EXT4.group_count {
        return;
    }

    if let Some(bg) = read_bg_info(group) {
        let mut bitmap = [0u8; 4096];
        if read_block(bg.block_bitmap_block, &mut bitmap) {
            let byte_idx = bit_pos / 8;
            let bit_idx = (bit_pos % 8) as u32;
            bitmap[byte_idx] &= !(1 << bit_idx);
            write_block(bg.block_bitmap_block, &bitmap);
            update_bg_free_blocks(group, bg.free_blocks_lo + 1);
        }
    }
}

/// test/ — 内核健全性测试套件
