/// ext4/inode.rs — Inode 读取与写入
use super::disk_io::{read_bytes, u16_at, u32_at, write_bytes, INODE_BUF};
use super::EXT4;

/// 从磁盘读取 inode 原始数据, 返回相关字段
///
/// 返回: (i_mode, i_size, i_flags, i_block[60 bytes])
pub(crate) unsafe fn read_raw_inode(ino: u32) -> Option<(u16, u64, u32, [u8; 60])> {
    debug_assert!(
        crate::hal::irq::is_disabled(),
        "read_raw_inode: INODE_BUF requires interrupts disabled"
    );
    if ino == 0 || !EXT4.initialized {
        return None;
    }

    let group = (ino - 1) / EXT4.inodes_per_group;
    let index_in_group = (ino - 1) % EXT4.inodes_per_group;

    if group >= EXT4.group_count {
        return None;
    }

    // 读块组描述符
    let bgdt_byte_offset =
        EXT4.bgdt_block as u64 * EXT4.block_size as u64 + group as u64 * EXT4.bg_desc_size as u64;

    let mut bg_buf = [0u8; 64];
    let read_len = if EXT4.bg_desc_size > 64 {
        64
    } else {
        EXT4.bg_desc_size as usize
    };
    if !read_bytes(bgdt_byte_offset, &mut bg_buf[..read_len]) {
        return None;
    }

    // inode 表起始块号
    let inode_table_lo = u32_at(&bg_buf, 0x08) as u64;
    let inode_table_hi = if EXT4.bg_desc_size >= 64 {
        u32_at(&bg_buf, 0x28) as u64
    } else {
        0u64
    };
    let inode_table_block = inode_table_lo | (inode_table_hi << 32);

    // inode 在 inode table 中的字节偏移
    let inode_byte_offset =
        inode_table_block * EXT4.block_size as u64 + index_in_group as u64 * EXT4.inode_size as u64;

    // 读取 inode (至少 128 字节)
    let read_size = if EXT4.inode_size > 256 {
        256
    } else {
        EXT4.inode_size as usize
    };
    if read_size > INODE_BUF.len() {
        return None;
    }
    if !read_bytes(inode_byte_offset, &mut INODE_BUF[..read_size]) {
        return None;
    }

    let i_mode = u16_at(&INODE_BUF, 0x00);
    let i_size_lo = u32_at(&INODE_BUF, 0x04) as u64;
    let i_size_hi = u32_at(&INODE_BUF, 0x6C) as u64; // i_size_high (EXT4)
    let i_size = i_size_lo | (i_size_hi << 32);
    let i_flags = u32_at(&INODE_BUF, 0x20);
    let i_links_count = u16_at(&INODE_BUF, 0x1A);

    // i_block[15] 区域: 60 字节, 从偏移 0x28 开始
    let mut i_block = [0u8; 60];
    i_block.copy_from_slice(&INODE_BUF[0x28..0x28 + 60]);

    let _ = i_links_count;

    Some((i_mode, i_size, i_flags, i_block))
}

/// 读取 inode 的 nlink
pub(crate) unsafe fn read_inode_nlink(ino: u32) -> u16 {
    if ino == 0 || !EXT4.initialized {
        return 0;
    }
    let group = (ino - 1) / EXT4.inodes_per_group;
    let index_in_group = (ino - 1) % EXT4.inodes_per_group;
    if group >= EXT4.group_count {
        return 0;
    }

    let bgdt_byte_offset =
        EXT4.bgdt_block as u64 * EXT4.block_size as u64 + group as u64 * EXT4.bg_desc_size as u64;
    let mut bg_buf = [0u8; 64];
    let read_len = if EXT4.bg_desc_size > 64 {
        64
    } else {
        EXT4.bg_desc_size as usize
    };
    if !read_bytes(bgdt_byte_offset, &mut bg_buf[..read_len]) {
        return 0;
    }

    let inode_table_lo = u32_at(&bg_buf, 0x08) as u64;
    let inode_table_hi = if EXT4.bg_desc_size >= 64 {
        u32_at(&bg_buf, 0x28) as u64
    } else {
        0
    };
    let inode_table_block = inode_table_lo | (inode_table_hi << 32);
    let inode_byte_offset =
        inode_table_block * EXT4.block_size as u64 + index_in_group as u64 * EXT4.inode_size as u64;

    let mut tmp = [0u8; 32];
    if !read_bytes(inode_byte_offset, &mut tmp) {
        return 0;
    }
    u16_at(&tmp, 0x1A)
}

