/// 计算 inode 在磁盘上的字节偏移
unsafe fn inode_byte_offset(ino: u32) -> Option<u64> {
    if ino == 0 || !EXT4.initialized {
        return None;
    }
    let group = (ino - 1) / EXT4.inodes_per_group;
    let index_in_group = (ino - 1) % EXT4.inodes_per_group;
    if group >= EXT4.group_count {
        return None;
    }

    let bgdt_byte_offset =
        EXT4.bgdt_block as u64 * EXT4.block_size as u64 + group as u64 * EXT4.bg_desc_size as u64;
    let mut bg_buf = [0u8; 64];
    let read_len = if EXT4.bg_desc_size > 64 {
        64
    } else {
        EXT4.bg_desc_size as usize
    };
    if !read_bytes(bgdt_byte_offset, &mut bg_buf[..read_len]) {
        return None;
    }

    let inode_table_lo = u32_at(&bg_buf, 0x08) as u64;
    let inode_table_hi = if EXT4.bg_desc_size >= 64 {
        u32_at(&bg_buf, 0x28) as u64
    } else {
        0
    };
    let inode_table_block = inode_table_lo | (inode_table_hi << 32);

    Some(
        inode_table_block * EXT4.block_size as u64 + index_in_group as u64 * EXT4.inode_size as u64,
    )
}

/// 更新 inode 的 i_size (低32位 + 高32位)
pub(crate) unsafe fn update_inode_size(ino: u32, new_size: u64) -> bool {
    let off = match inode_byte_offset(ino) {
        Some(o) => o,
        None => return false,
    };
    let size_lo = (new_size & 0xFFFF_FFFF) as u32;
    let size_hi = (new_size >> 32) as u32;
    write_bytes(off + 0x04, &size_lo.to_le_bytes())
        && write_bytes(off + 0x6C, &size_hi.to_le_bytes())
}

/// 更新 inode 的 i_links_count
pub(crate) unsafe fn update_inode_nlink(ino: u32, nlink: u16) -> bool {
    let off = match inode_byte_offset(ino) {
        Some(o) => o,
        None => return false,
    };
    write_bytes(off + 0x1A, &nlink.to_le_bytes())
}

/// 写回 inode 的 i_block (60字节 extent 树根)
pub(crate) unsafe fn write_inode_iblock(ino: u32, i_block: &[u8; 60]) -> bool {
    let off = match inode_byte_offset(ino) {
        Some(o) => o,
        None => return false,
    };
    write_bytes(off + 0x28, i_block)
}

/// 初始化一个新分配的 inode (清零 + 设置 mode/flags/nlink/extent header)
///
/// mode: 文件类型 + 权限位 (如 0o100644 = regular file rw-r--r--)
pub(crate) unsafe fn init_new_inode(ino: u32, mode: u16, is_dir: bool) -> bool {
    let off = match inode_byte_offset(ino) {
        Some(o) => o,
        None => return false,
    };

    // 清零整个 inode
    let isize = EXT4.inode_size as usize;
    let zeros = [0u8; 256];
    let clear_len = isize.min(256);
    if !write_bytes(off, &zeros[..clear_len]) {
        return false;
    }

    // i_mode
    if !write_bytes(off + 0x00, &mode.to_le_bytes()) {
        return false;
    }

    // i_links_count = 1 (目录后续 dir_add_entry 会增加)
    let nlink: u16 = if is_dir { 2 } else { 1 };
    if !write_bytes(off + 0x1A, &nlink.to_le_bytes()) {
        return false;
    }

    // i_flags = EXT4_EXTENTS_FL
    let flags: u32 = super::EXT4_EXTENTS_FL;
    if !write_bytes(off + 0x20, &flags.to_le_bytes()) {
        return false;
    }

    // i_block: 初始化 extent header (空树)
    let mut i_block = [0u8; 60];
    // eh_magic
    i_block[0] = 0x0A;
    i_block[1] = 0xF3;
    // eh_entries = 0
    i_block[2] = 0;
    i_block[3] = 0;
    // eh_max = (60 - 12) / 12 = 4
    i_block[4] = 4;
    i_block[5] = 0;
    // eh_depth = 0
    i_block[6] = 0;
    i_block[7] = 0;
    write_bytes(off + 0x28, &i_block)
}

