/// 在目录 inode 中查找名为 name 的条目
/// 返回子 inode 号
pub(crate) unsafe fn dir_lookup(dir_ino: u32, name: &[u8]) -> Option<u32> {
    let (i_mode, i_size, i_flags, i_block) = match read_raw_inode(dir_ino) {
        Some(x) => x,
        None => return None,
    };

    if i_mode & 0xF000 != EXT4_S_IFDIR {
        return None;
    }

    if i_flags & EXT4_EXTENTS_FL == 0 {
        return None;
    }

    let bs = EXT4.block_size as usize;
    let dir_size = i_size as usize;
    let mut pos = 0usize;

    while pos < dir_size {
        let logical_block = (pos / bs) as u64;
        let phys_block = match extent_map_block(&i_block, logical_block) {
            Some(pb) => pb,
            None => {
                pos += bs;
                continue;
            }
        };

        let mut dir_blk = [0u8; 4096];
        if !read_block(phys_block, &mut dir_blk) {
            break;
        }

        let block_end = if dir_size - pos < bs {
            dir_size - pos
        } else {
            bs
        };
        let mut off = 0usize;

        while off + 8 <= block_end {
            let de_inode = u32_at(&dir_blk, off);
            let de_rec_len = u16_at(&dir_blk, off + 4) as usize;
            let de_name_len = dir_blk[off + 6] as usize;

            if de_rec_len == 0 {
                break;
            }

            if de_inode != 0 && de_name_len == name.len() {
                if off + 8 + de_name_len <= dir_blk.len() {
                    let de_name = &dir_blk[off + 8..off + 8 + de_name_len];
                    if de_name == name {
                        return Some(de_inode);
                    }
                }
            }

            off += de_rec_len;
        }

        pos += bs;
    }

    None
}

/// 读取目录的第 index 个条目 (跳过 . 和 ..)
///
/// 返回 (name, name_len, child_ino, inode_type)
pub(crate) unsafe fn dir_readdir(
    dir_ino: u32,
    index: usize,
) -> Option<([u8; NAME_BUF_LEN], u8, u32, InodeType)> {
    let (i_mode, i_size, i_flags, i_block) = match read_raw_inode(dir_ino) {
        Some(x) => x,
        None => return None,
    };

    if i_mode & 0xF000 != EXT4_S_IFDIR {
        return None;
    }

    if i_flags & EXT4_EXTENTS_FL == 0 {
        return None;
    }

    let bs = EXT4.block_size as usize;
    let dir_size = i_size as usize;
    let mut pos = 0usize;
    let mut cur_index = 0usize;

    while pos < dir_size {
        let logical_block = (pos / bs) as u64;
        let phys_block = match extent_map_block(&i_block, logical_block) {
            Some(pb) => pb,
            None => {
                pos += bs;
                continue;
            }
        };

        let mut dir_blk = [0u8; 4096];
        if !read_block(phys_block, &mut dir_blk) {
            break;
        }

        let block_end = if dir_size - pos < bs {
            dir_size - pos
        } else {
            bs
        };
        let mut off = 0usize;

        while off + 8 <= block_end {
            let de_inode = u32_at(&dir_blk, off);
            let de_rec_len = u16_at(&dir_blk, off + 4) as usize;
            let de_name_len = dir_blk[off + 6] as usize;
            let de_file_type = dir_blk[off + 7];

            if de_rec_len == 0 {
                break;
            }

            if de_inode != 0 && de_name_len > 0 {
                if cur_index == index {
                    let mut name = [0u8; NAME_BUF_LEN];
                    let copy_len = if de_name_len > NAME_BUF_LEN {
                        NAME_BUF_LEN
                    } else {
                        de_name_len
                    };
                    if off + 8 + copy_len <= dir_blk.len() {
                        name[..copy_len].copy_from_slice(&dir_blk[off + 8..off + 8 + copy_len]);
                    }

                    let itype = match de_file_type {
                        EXT4_FT_DIR => InodeType::Dir,
                        EXT4_FT_CHRDEV => InodeType::CharDev,
                        _ => InodeType::File,
                    };

                    return Some((name, copy_len as u8, de_inode, itype));
                }
                cur_index += 1;
            }

            off += de_rec_len;
        }

        pos += bs;
    }

    None
}

