/// 将 InodeType 转为 ext4 dir entry file_type
fn itype_to_ft(itype: InodeType) -> u8 {
    match itype {
        InodeType::Dir => EXT4_FT_DIR,
        InodeType::CharDev => EXT4_FT_CHRDEV,
        _ => EXT4_FT_REG_FILE,
    }
}

/// 在目录 dir_ino 中添加一个新条目
///
/// 策略: 遍历目录已有数据块, 在 dirent 的空闲空间中插入;
///       若当前块放不下, 分配新数据块
pub(crate) unsafe fn dir_add_entry(
    dir_ino: u32,
    name: &[u8],
    child_ino: u32,
    itype: InodeType,
) -> bool {
    let (i_mode, i_size, i_flags, mut i_block) = match read_raw_inode(dir_ino) {
        Some(x) => x,
        None => return false,
    };

    if i_mode & 0xF000 != EXT4_S_IFDIR {
        return false;
    }
    if i_flags & EXT4_EXTENTS_FL == 0 {
        return false;
    }

    let bs = EXT4.block_size as usize;
    let dir_size = i_size as usize;
    let ft = itype_to_ft(itype);

    // 新 entry 需要的最小字节数 (8 字节头 + name_len, 4字节对齐)
    let need = (8 + name.len() + 3) & !3;

    // 遍历已有数据块, 尝试在 dirent 的空闲空间中插入
    let total_blocks = (dir_size + bs - 1) / bs;
    for blk_idx in 0..total_blocks {
        let logical_block = blk_idx as u64;
        let phys_block = match extent_map_block(&i_block, logical_block) {
            Some(pb) => pb,
            None => continue,
        };

        let mut dir_blk = [0u8; 4096];
        if !read_block(phys_block, &mut dir_blk) {
            continue;
        }

        // 扫描这个块, 找有空闲空间的 dirent
        let mut off = 0usize;
        while off + 8 <= bs {
            let de_rec_len = u16_at(&dir_blk, off + 4) as usize;
            if de_rec_len == 0 {
                break;
            }

            let de_inode = u32_at(&dir_blk, off);
            let de_name_len = dir_blk[off + 6] as usize;

            // 这个 dirent 实际占用的字节
            let actual = if de_inode == 0 {
                0 // 被删除的 entry, 可完全复用其 rec_len
            } else {
                (8 + de_name_len + 3) & !3
            };

            let free_space = de_rec_len - actual;
            if free_space >= need {
                // 切割: 缩小当前 entry 的 rec_len, 在后面写新 entry
                if actual > 0 {
                    let new_cur_rec = actual as u16;
                    dir_blk[off + 4] = new_cur_rec as u8;
                    dir_blk[off + 5] = (new_cur_rec >> 8) as u8;
                }

                let new_off = off + actual;
                let new_rec_len = (de_rec_len - actual) as u16;
                write_dirent(&mut dir_blk, new_off, child_ino, new_rec_len, name, ft);
                write_block(phys_block, &dir_blk);
                return true;
            }

            off += de_rec_len;
        }
    }

    // 没有块有空间: 分配新数据块
    let new_phys = match alloc_block() {
        Some(b) => b,
        None => return false,
    };
    let new_logical = total_blocks as u64;

    if !extent_append(&mut i_block, new_logical, new_phys) {
        return false;
    }
    write_inode_iblock(dir_ino, &i_block);

    // 在新块中写入一个 dirent, rec_len = 整个块
    let mut new_blk = [0u8; 4096];
    write_dirent(&mut new_blk, 0, child_ino, bs as u16, name, ft);
    write_block(new_phys, &new_blk);

    // 更新目录 i_size
    let new_size = (total_blocks + 1) * bs;
    update_inode_size(dir_ino, new_size as u64);

    true
}

