/// ext4/read.rs — 文件读取 (通过 extent 映射)
use super::disk_io::read_block;
use super::extent::extent_map_block;
use super::inode::read_raw_inode;
use super::{EXT4, EXT4_EXTENTS_FL, EXT4_S_IFDIR, EXT4_S_IFREG};

/// 读取 inode 的数据 (通过 extent 映射)
///
/// 从 offset 开始读 buf.len() 字节, 返回实际读取字节数
pub(crate) unsafe fn read_inode_data(ino: u32, offset: usize, buf: &mut [u8]) -> isize {
    let (i_mode, i_size, i_flags, i_block) = match read_raw_inode(ino) {
        Some(x) => x,
        None => return -5, // EIO
    };

    let mode_type = i_mode & 0xF000;
    if mode_type != EXT4_S_IFREG && mode_type != EXT4_S_IFDIR {
        return -1; // EPERM
    }

    if offset >= i_size as usize {
        return 0;
    }

    let available = i_size as usize - offset;
    let to_read = if buf.len() < available {
        buf.len()
    } else {
        available
    };

    if i_flags & EXT4_EXTENTS_FL == 0 {
        return -95; // EOPNOTSUPP
    }

    let bs = EXT4.block_size as usize;
    let mut read_total = 0usize;
    let mut file_pos = offset;

    while read_total < to_read {
        let logical_block = (file_pos / bs) as u64;
        let offset_in_block = file_pos % bs;

        let phys_block = extent_map_block(&i_block, logical_block);

        let remaining = to_read - read_total;
        let avail_in_block = bs - offset_in_block;
        let chunk = if remaining < avail_in_block {
            remaining
        } else {
            avail_in_block
        };

        if let Some(pb) = phys_block {
            let mut blk_data = [0u8; 4096];
            if !read_block(pb, &mut blk_data) {
                break;
            }
            buf[read_total..read_total + chunk]
                .copy_from_slice(&blk_data[offset_in_block..offset_in_block + chunk]);
        } else {
            // Sparse block (hole): fill with zeros
            for b in &mut buf[read_total..read_total + chunk] {
                *b = 0;
            }
        }

        read_total += chunk;
        file_pos += chunk;
    }

    read_total as isize
}

