pub fn devfs_read(_fs_id: u8, fs_inode: u32, _offset: usize, buf: &mut [u8]) -> isize {
    match fs_inode {
        DEV_CONSOLE => {
            let mut count = 0usize;
            for byte_slot in buf.iter_mut() {
                if let Some(b) = crate::tty::tty_getc() {
                    *byte_slot = b;
                    count += 1;
                } else {
                    break;
                }
            }
            count as isize
        }
        DEV_NULL | DEV_CPU_DMA_LATENCY => 0,
        DEV_ZERO => {
            for b in buf.iter_mut() {
                *b = 0;
            }
            buf.len() as isize
        }
        DEV_URANDOM => {
            let mut seed = crate::hal::time::read_ticks();
            for b in buf.iter_mut() {
                seed ^= seed << 13;
                seed ^= seed >> 7;
                seed ^= seed << 17;
                *b = seed as u8;
            }
            buf.len() as isize
        }
        DEV_MISC_RTC => {
            // hwclock reads RTC via ioctl, not read(); return 0 bytes
            0
        }
        _ => -9,
    }
}

pub fn devfs_write(_fs_id: u8, fs_inode: u32, _offset: usize, buf: &[u8]) -> isize {
    match fs_inode {
        DEV_CONSOLE => {
            for &b in buf {
                crate::tty::tty_putc(b);
            }
            buf.len() as isize
        }
        DEV_NULL | DEV_ZERO | DEV_URANDOM | DEV_CPU_DMA_LATENCY => buf.len() as isize,
        _ => -9,
    }
}

/// Device-specific ioctl handler
///
/// Returns:
///   >= 0: success
///   -ENOTTY: not a supported ioctl for this device
///   -EFAULT: bad user buffer
pub fn devfs_ioctl(fs_inode: u32, cmd: u32, arg: usize) -> isize {
    match (fs_inode, cmd) {
        (DEV_CONSOLE, TIOCGWINSZ) => {
            if arg == 0 {
                return -errno::EFAULT;
            }
            let mut bytes = [0u8; 8];
            bytes[0..2].copy_from_slice(&24u16.to_le_bytes());
            bytes[2..4].copy_from_slice(&80u16.to_le_bytes());
            if let Err(e) = crate::syscall::check::write_bytes_to_user(arg, &bytes) {
                return e;
            }
            0
        }
        (DEV_MISC_RTC, RTC_RD_TIME) => {
            if arg == 0 {
                return -errno::EFAULT;
            }
            let vals: [i32; 9] = [0, 0, 0, 1, 0, 124, 1, 0, 0];
            let bytes = unsafe {
                core::slice::from_raw_parts(vals.as_ptr() as *const u8, core::mem::size_of_val(&vals))
            };
            if let Err(e) = crate::syscall::check::write_bytes_to_user(arg, bytes) {
                return e;
            }
            0
        }
        _ => -errno::ENOTTY,
    }
}

pub fn devfs_lookup(_fs_id: u8, dir_fs_inode: u32, name: &[u8]) -> Option<u32> {
    if dir_fs_inode == DEV_ROOT {
        if name == b"." {
            return Some(DEV_ROOT);
        }
        if name == b".." {
            return Some(DEV_ROOT);
        }
        return match name {
            b"console" | b"tty" => Some(DEV_CONSOLE),
            b"null" => Some(DEV_NULL),
            b"zero" => Some(DEV_ZERO),
            b"misc" => Some(DEV_MISC),
            b"urandom" | b"random" => Some(DEV_URANDOM),
            b"rtc" | b"rtc0" => Some(DEV_MISC_RTC),
            b"cpu_dma_latency" => Some(DEV_CPU_DMA_LATENCY),
            b"shm" => Some(DEV_SHM),
            _ => None,
        };
    }
    if dir_fs_inode == DEV_MISC {
        if name == b"." {
            return Some(DEV_MISC);
        }
        if name == b".." {
            return Some(DEV_ROOT);
        }
        return match name {
            b"rtc" => Some(DEV_MISC_RTC),
            _ => None,
        };
    }
    None
}

