const VIRTIO_BLK_T_IN:     u32 = 0;
const VIRTIO_BLK_T_OUT:    u32 = 1;
const VRING_DESC_F_NEXT:    u16 = 1;
const VRING_DESC_F_WRITE:   u16 = 2;

const VIRTIO_MMIO_BASE:   usize = 0x1000_1000;
const VIRTIO_MMIO_SLOTS:  usize = 1;
const VIRTIO_MMIO_STRIDE: usize = 0x1000;

const QUEUE_SIZE: usize = 8;
const PAGE_SIZE:  usize = 4096;
pub const SECTOR_SIZE: usize = 512;

// ─── Virtqueue 数据结构 ─────────────────────────────────

#[derive(Copy, Clone)]
#[repr(C)]
struct VirtqDesc {
    addr:  u64,
    len:   u32,
    flags: u16,
    next:  u16,
}

#[repr(C)]
struct VringAvail {
    flags: u16,
    idx:   u16,
    ring:  [u16; QUEUE_SIZE],
}

#[derive(Copy, Clone)]
#[repr(C)]
struct VringUsedElem {
    id:  u32,
    len: u32,
}

#[repr(C)]
struct VringUsed {
    flags: u16,
    idx:   u16,
    ring:  [VringUsedElem; QUEUE_SIZE],
}

#[repr(C)]
struct VirtioBlkReq {
    type_:    u32,
    reserved: u32,
    sector:   u64,
}

#[repr(C, align(4096))]
struct VringMem {
    bytes: [u8; 2 * PAGE_SIZE],
}

static mut VRING_MEM: VringMem = VringMem { bytes: [0u8; 2 * PAGE_SIZE] };
static mut REQ_HEADER: VirtioBlkReq = VirtioBlkReq { type_: 0, reserved: 0, sector: 0 };
static mut REQ_STATUS: u8 = 0xFF;

struct BlkState {
    base: usize,
    initialized: bool,
    version: u32,
    last_used_idx: u16,
    capacity: u64,
    desc:  *mut VirtqDesc,
    avail: *mut VringAvail,
    used:  *mut VringUsed,
}

static mut BLK: BlkState = BlkState {
    base: 0, initialized: false, version: 0, last_used_idx: 0, capacity: 0,
    desc: core::ptr::null_mut(), avail: core::ptr::null_mut(), used: core::ptr::null_mut(),
};

unsafe fn mmio_read32(base: usize, offset: usize) -> u32 {
    ((base + offset) as *const u32).read_volatile()
}

unsafe fn mmio_write32(base: usize, offset: usize, val: u32) {
    ((base + offset) as *mut u32).write_volatile(val);
}

// ─── 公开接口 ───────────────────────────────────────────

pub fn probe() -> bool {
    unsafe {
        for slot in 0..VIRTIO_MMIO_SLOTS {
            let base = VIRTIO_MMIO_BASE + slot * VIRTIO_MMIO_STRIDE;
            let magic = mmio_read32(base, MMIO_MAGIC_VALUE);
            if magic != VIRTIO_MAGIC { continue; }
            let device_id = mmio_read32(base, MMIO_DEVICE_ID);
            if device_id != VIRTIO_BLK_DEVICE_ID { continue; }
            let version = mmio_read32(base, MMIO_VERSION);
            crate::kinfo!("found at {:#x}, version={}", base, version);
            if version != 1 && version != 2 {
                crate::kwarn!("unsupported version {}", version);
                continue;
            }
            return io::init_device(base, version);
        }
        crate::kwarn!("no block device found");
        false
    }
}

pub fn is_available() -> bool { unsafe { BLK.initialized } }
pub fn capacity() -> u64 { unsafe { BLK.capacity } }

pub fn read_sector(sector: u64, buf: &mut [u8]) -> bool {
    if buf.len() < SECTOR_SIZE { return false; }
    unsafe {
        if !BLK.initialized || sector >= BLK.capacity { return false; }
        let guard = crate::hal::irq::disable();
        let ok = io::block_io(VIRTIO_BLK_T_IN, sector, buf.as_mut_ptr(), SECTOR_SIZE);
        crate::hal::irq::restore(guard);
        ok
    }
}

pub fn write_sector(sector: u64, buf: &[u8]) -> bool {
    if buf.len() < SECTOR_SIZE { return false; }
    unsafe {
        if !BLK.initialized || sector >= BLK.capacity { return false; }
        let guard = crate::hal::irq::disable();
        let ok = io::block_io(VIRTIO_BLK_T_OUT, sector, buf.as_ptr() as *mut u8, SECTOR_SIZE);
        crate::hal::irq::restore(guard);
        ok
    }
}

#[allow(dead_code)]
pub fn read_sectors(start_sector: u64, count: usize, buf: &mut [u8]) -> bool {
    let total = count * SECTOR_SIZE;
    if buf.len() < total { return false; }
    for i in 0..count {
        let off = i * SECTOR_SIZE;
        if !read_sector(start_sector + i as u64, &mut buf[off..off + SECTOR_SIZE]) {
            return false;
        }
    }
    true
}

#[allow(dead_code)]
pub fn write_sectors(start_sector: u64, count: usize, buf: &[u8]) -> bool {
    let total = count * SECTOR_SIZE;
    if buf.len() < total { return false; }
    for i in 0..count {
        let off = i * SECTOR_SIZE;
        if !write_sector(start_sector + i as u64, &buf[off..off + SECTOR_SIZE]) {
            return false;
        }
    }
    true
}

