///
/// 提供 busybox 所需的关键 /proc 文件:
///   /proc/mounts    — 挂载信息 (df 需要)
///   /proc/meminfo   — 内存统计 (free 需要)
///   /proc/{pid}/    — 进程目录 (ps 需要)
///   /proc/{pid}/stat — 进程状态
///   /proc/self/     — 当前进程 (symlink 到 pid)
///
/// 所有内容动态生成, 零磁盘存储。
use super::{InodeType, Stat, NAME_BUF_LEN, S_IFDIR, S_IFREG};

// ─── 虚拟 Inode 编号方案 ────────────────────────────────
//
// 0         = /proc 根目录
// 1         = /proc/mounts
// 2         = /proc/meminfo
// 100+pid   = /proc/{pid} 目录
// 10000+pid = /proc/{pid}/stat
//
const PROC_ROOT: u32 = 0;
const PROC_MOUNTS: u32 = 1;
const PROC_MEMINFO: u32 = 2;
const PROC_CPUINFO: u32 = 3;
const PROC_PID_BASE: u32 = 100;
const PROC_PID_STAT_BASE: u32 = 10000;

// ─── 辅助: 数字 → 字节 ──────────────────────────────────

fn usize_to_bytes(mut n: usize, buf: &mut [u8]) -> usize {
    if n == 0 {
        if !buf.is_empty() {
            buf[0] = b'0';
        }
        return 1;
    }
    let mut tmp = [0u8; 20];
    let mut len = 0;
    while n > 0 {
        tmp[len] = b'0' + (n % 10) as u8;
        n /= 10;
        len += 1;
    }
    // reverse into buf
    let copy_len = if len > buf.len() { buf.len() } else { len };
    for i in 0..copy_len {
        buf[i] = tmp[len - 1 - i];
    }
    copy_len
}

fn parse_u32(s: &[u8]) -> Option<u32> {
    if s.is_empty() {
        return None;
    }
    let mut val: u32 = 0;
    for &b in s {
        if b < b'0' || b > b'9' {
            return None;
        }
        val = val.checked_mul(10)?.checked_add((b - b'0') as u32)?;
    }
    Some(val)
}

