/// - read_file_to_pages(): VFS 文件读取到物理页框
use crate::hal::irq;
use crate::hal::mmu::{activate, AddressSpaceToken};
use crate::hal::trap::UserTrapFrame;
use crate::loader::{free_pages, read_file_to_pages, ElfBuf};
use crate::mm::address::{PhysAddr, PhysPageNum};

// ─── exec 主入口 ─────────────────────────────────────────

/// exec: 从 VFS 加载 ELF 文件并替换当前进程映像
///
/// 支持静态 ET_EXEC 和动态 ET_DYN (PIE + 动态链接器)
///
/// 流程:
///   1. 通过 VFS 打开路径指向的文件
///   2. fstat 获取文件大小, 动态分配页框作为临时 ELF 缓冲区
///   3. 读取文件内容到分配的页框 (支持非连续页)
///   4. 调用 load_elf_from_pages:
///      - 若返回 NeedsInterp, 从 VFS 加载解释器并重新调用
///   5. 释放临时 ELF 页框
///   6. 替换 TCB 的地址空间 (旧 AS Drop → 回收用户帧)
///   7. 重写内核栈上的 TrapContext
///   8. 切换 satp 到新地址空间
pub fn exec_current_path(path: &[u8], argv: &[&[u8]], envp: &[&[u8]]) -> isize {
    /// 主 ELF 最大页数 (512 页 = 2MB, 4KB 栈空间; busybox 需要 362 页)
    const MAIN_MAX_PAGES: usize = 512;

    let guard = irq::disable();
    let result = unsafe {
        assert!(
            super::manager::MANAGER.initialized,
            "task manager not initialized"
        );
        let cur = super::manager::MANAGER.current;
        assert!(cur != 0, "exec: idle cannot exec");

        let cwd = super::manager::MANAGER.tasks[cur]
            .as_ref()
            .unwrap()
            .cwd_inode;

        // ── 读取主 ELF 文件到页框 ──
        let mut main_frames: [PhysPageNum; MAIN_MAX_PAGES] =
            [PhysPageNum::from(0usize); MAIN_MAX_PAGES];
        let main_count: usize;
        let main_len: usize;
        match read_file_to_pages(cwd, path, &mut main_frames) {
            Ok((count, len)) => {
                main_count = count;
                main_len = len;
            }
            Err(e) => {
                irq::restore(guard);
                return e;
            }
        }

        // ── 第一次尝试加载 (无解释器) ──
        let elf_buf = ElfBuf {
            frames: &main_frames[..main_count],
            len: main_len,
        };
        let load_result = crate::loader::load_elf_from_pages(&elf_buf, None, argv, envp);

        let (load_info, used_interp) = match load_result {
            Ok(info) => (info, false),
            Err(crate::loader::ElfError::NeedsInterp(interp_path, interp_plen)) => {
                // 需要动态链接器 — 委托给单独函数以管理栈空间
                match exec_load_with_interp(
                    &main_frames[..main_count],
                    main_len,
                    &interp_path,
                    interp_plen,
                    argv,
                    envp,
                ) {
                    Ok(info) => (info, true),
                    Err(e) => {
                        free_pages(&main_frames, main_count);
                        irq::restore(guard);
                        return e;
                    }
                }
            }
            Err(_e) => {
                // 检查是否是脚本文件 (#! shebang)
                let first_pa: usize = PhysAddr::from(main_frames[0]).into();
                let first_bytes =
                    core::slice::from_raw_parts(first_pa as *const u8, main_len.min(256));
                if main_len >= 2 && first_bytes[0] == b'#' && first_bytes[1] == b'!' {
                    // 解析 shebang: 提取解释器路径
                    // 找到第一行末尾 (或 256 字节内)
                    let mut line_end = 2;
                    while line_end < first_bytes.len() && first_bytes[line_end] != b'\n' {
                        line_end += 1;
                    }
                    // 跳过 #! 后的空格
                    let mut interp_start = 2;
