/// 当前任务退出
///
/// 释放地址空间和内核栈 (昂贵资源), 但保留 TCB 槽位 (Zombie 状态)。
/// 父进程 waitpid 时才最终回收 PID 和 TCB 槽位。
///
/// killed_by_signal: 如果进程被信号终止, 传入 Some(signum); 正常退出传 None。
/// 这影响 waitpid 返回的 wstatus 编码:
///   - None → WIFEXITED, exit_code 为正常退出码
///   - Some(sig) → WIFSIGNALED, 信号为 sig
pub fn exit_current(exit_code: i32, killed_by_signal: Option<u32>) -> ! {
    // 关中断, 无需 restore (-> ! 永远不返回)
    irq::disable();
    unsafe {
        assert!(MANAGER.initialized, "task manager not initialized");

        // 延迟回收: 上一次 exit_current 留下的 orphan TCB
        for i in 0..MANAGER.pending_reap_count {
            let pid = MANAGER.pending_reap[i];
            if pid != 0 {
                MANAGER.tasks[pid] = None;
                MANAGER.pending_reap[i] = 0;
            }
        }
        MANAGER.pending_reap_count = 0;

        let cur = MANAGER.current; // 读取当前 PID
        assert!(cur != 0, "exit_current: idle (PID 0) cannot exit"); // idle 不允许退出

        // PID 1 (init) 退出 → 内核直接关机
        if cur == 1 {
            crate::kinfo!(
                "init (PID 1) exited with code {} — shutting down",
                exit_code
            );
            firmware::shutdown();
        }

        let parent_pid;
        let is_thread;
        {
            let tcb = MANAGER.tasks[cur].as_mut().unwrap();
            parent_pid = tcb.parent_pid;
            is_thread = tcb.addr_space_owner != cur;
            tcb.killed_by_signal = killed_by_signal;

            if tcb.clear_child_tid != 0 {
                crate::sched::clear_child_tid_and_wake(cur, tcb.clear_child_tid);
                tcb.clear_child_tid = 0;
            }

            let ks = kernel_token().0;
            activate(AddressSpaceToken(ks));
            tcb.satp_val = 0;
            drop(tcb.addr_space.take());

            // 关闭所有 fd 的引用计数
            for i in 0..MAX_FDS {
                super::fd::fd_close_resource(tcb.fd_table[i]);
                tcb.fd_table[i] = FdKind::None;
            }
            // vfork 唤醒: 若本进程是 vfork 子进程且父进程正在等待, 则将父进程唤醒
            let vfork_waiter = tcb.vfork_waiter;
            tcb.vfork_waiter = 0;
            if vfork_waiter != 0 {
                if let Some(parent) = MANAGER.tasks[vfork_waiter].as_mut() {
                    if parent.state == TaskState::Blocked {
                        parent.state = TaskState::Ready;
                        parent.time_slice = DEFAULT_TIME_SLICE;
                        MANAGER.push_runnable(vfork_waiter);
                    }
                }
            }

