///
/// 从 manager.rs 拆分而来:
/// - send_signal(): 发送信号给指定进程
/// - deliver_pending_signals(): 返回用户态前投递待处理信号
/// - do_sigreturn(): 从信号帧恢复原始 TrapContext

use crate::hal::irq;
use crate::hal::trap::UserTrapFrame;
use crate::sched::task::{TaskControlBlock, TaskState, MAX_TASKS};
use crate::sched::signal::{
    self, SIGKILL, SIGCHLD, SIG_DFL, SIG_IGN, DefaultAction,
