fn notify_parent_sigchld(parent_pid: usize) {
    if parent_pid == 0 || parent_pid >= MAX_TASKS {
        return;
    }
    let parent = match unsafe { MANAGER.tasks[parent_pid].as_mut() } {
        Some(tcb) if tcb.state != TaskState::Zombie && tcb.state != TaskState::Exited => tcb,
        _ => return,
    };

    let parent_waiting = parent.waiting_for_child;
    let parent_has_sigchld_handler = parent.signal.has_handler(SIGCHLD);
    parent.signal.raise(SIGCHLD);

    if parent.state == TaskState::Blocked
        && (parent_waiting || parent_has_sigchld_handler)
    {
        parent.state = TaskState::Ready;
        parent.waiting_for_child = false;
        parent.time_slice = DEFAULT_TIME_SLICE;
        unsafe {
            MANAGER.push_runnable(parent_pid);
        }
    }
}

/// 发送信号给指定进程
///
/// 返回:  0 = 成功,  -ESRCH = 进程不存在,  -EINVAL = 无效信号
///
/// SIGKILL 特殊处理:
///   - 目标是当前进程 → 立即 exit_current (此函数不返回)
///   - 目标处于 Blocked 状态 → 唤醒 (放入就绪队列), 待 trap 返回时投递
pub fn send_signal(target_pid: usize, sig: u32) -> isize {
    if sig == 0 || sig >= signal::NSIG {
        return -crate::errno::EINVAL;
    }

    let guard = irq::disable();
    let (result, kill_self) = unsafe {
        if !MANAGER.initialized {
            (-crate::errno::ESRCH, false)
        } else if target_pid == 0 || target_pid >= MAX_TASKS {
            (-crate::errno::ESRCH, false)
        } else {
            match MANAGER.tasks[target_pid].as_mut() {
                Some(tcb) if tcb.state != TaskState::Zombie
                          && tcb.state != TaskState::Exited
                          && tcb.state != TaskState::UnInit =>
                {
                    tcb.signal.raise(sig);

                    // Wake blocked tasks for any deliverable signal (not just SIGKILL/sleep)
                    // This ensures SIGTERM/SIGINT etc. interrupt blocking syscalls
                    if tcb.state == TaskState::Blocked {
                        let action = tcb.signal.get_action(sig);
                        let is_deliverable = sig != crate::sched::signal::SIGCHLD
                            && (sig == crate::sched::signal::SIGKILL
                            || (action.handler != crate::sched::signal::SIG_IGN
                                && (tcb.signal.blocked >> sig) & 1 == 0));
                        if is_deliverable {
                            tcb.sleep_deadline = 0;
                            tcb.sleep_interrupted = true;
                            tcb.state = TaskState::Ready;
                            tcb.time_slice = DEFAULT_TIME_SLICE;
                            MANAGER.push_runnable(target_pid);
                        }
                    }

                    if tcb.state == TaskState::Stopped {
                        if sig == crate::sched::signal::SIGCONT || sig == SIGKILL {
                            tcb.state = TaskState::Ready;
                            tcb.time_slice = DEFAULT_TIME_SLICE;
                            MANAGER.push_runnable(target_pid);
                        }
                    }

                    let is_self = target_pid == MANAGER.current;
                    (0isize, is_self && sig == SIGKILL)

