/// 从非连续页框加载 ELF64 (支持 ET_EXEC + ET_DYN + 动态链接)
///
/// 对于 ET_DYN (PIE), 主程序加载到 ELF_DYN_BASE, 解释器加载到 INTERP_BASE。
/// 入口点 = 解释器 entry (若有) 或 主程序 entry。
pub fn load_elf_from_pages(
    buf: &ElfBuf,
    interp_buf: Option<&ElfBuf>,
    argv: &[&[u8]],
    envp: &[&[u8]],
) -> Result<ElfLoadInfo, ElfError> {
    let hdr_size = core::mem::size_of::<Elf64Header>();
    if buf.len < hdr_size {
        return Err(ElfError::TooShort);
    }

    let mut hdr_bytes = [0u8; 64];
    buf.read_at(0, &mut hdr_bytes[..hdr_size]);
    let header = unsafe { &*(hdr_bytes.as_ptr() as *const Elf64Header) };

    if header.e_ident[0..4] != ELF_MAGIC {
        return Err(ElfError::BadMagic);
    }
    if header.e_ident[4] != ELFCLASS64 {
        return Err(ElfError::Not64Bit);
    }
    if header.e_ident[5] != ELFDATA2LSB {
        return Err(ElfError::NotLittleEndian);
    }
    if header.e_type != ET_EXEC && header.e_type != ET_DYN {
        return Err(ElfError::NotExec);
    }
    if header.e_machine != EM_RISCV {
        return Err(ElfError::NotRiscV);
    }

    let is_dyn = header.e_type == ET_DYN;
    let base: usize = if is_dyn { ELF_DYN_BASE } else { 0 };
    let prog_entry = header.e_entry as usize + base;
    let ph_off = header.e_phoff as usize;
    let ph_size = core::mem::size_of::<Elf64ProgramHeader>();
    let ph_num = header.e_phnum as usize;

    let ph_end = ph_off
        .checked_add(
            ph_num
                .checked_mul(ph_size)
                .ok_or(ElfError::BadProgramHeader)?,
        )
        .ok_or(ElfError::BadProgramHeader)?;
    if ph_end > buf.len {
        return Err(ElfError::BadProgramHeader);
    }

    // 检查 PT_INTERP (ET_EXEC + PT_INTERP 也合法)
    if interp_buf.is_none() {
        let mut ph_tmp = [0u8; 56];
        for i in 0..ph_num {
            buf.read_at(ph_off + i * ph_size, &mut ph_tmp[..ph_size]);
            let ph = unsafe { &*(ph_tmp.as_ptr() as *const Elf64ProgramHeader) };
            if ph.p_type == PT_INTERP {
                let interp_off = ph.p_offset as usize;
                let interp_len = ph.p_filesz as usize;
                if interp_len > 0 && interp_len < 256 {
                    let mut path = [0u8; 256];
                    buf.read_at(interp_off, &mut path[..interp_len]);
                    let plen = if interp_len > 0 && path[interp_len - 1] == 0 {
                        interp_len - 1
                    } else {
                        interp_len
                    };
                    return Err(ElfError::NeedsInterp(path, plen));
                }
            }
