# OSKernel Makefile
#
# 用法:
#   make              - 编译 riscv64 (默认)
#   make ARCH=amd64   - 编译 amd64
#   make run          - 编译并运行
#   make debug        - 编译并以调试模式运行
#   make test         - 用比赛测试镜像启动 QEMU
#   make clean        - 清理构建产物
#
# 比赛评测:
#   make all          - 生成 kernel-rv 和 kernel-la (比赛评测入口)

# 默认架构
ARCH ?= riscv64

# 辅助: Make 函数中不能直接使用逗号
comma := ,

# 目录
ROOT_DIR    := $(shell pwd)
KERNEL_DIR  := $(ROOT_DIR)/kernel
BUILD_DIR   := $(ROOT_DIR)/build
TOOLS_DIR   := $(ROOT_DIR)/tools
USER_DIR    := $(ROOT_DIR)/user

# 根据架构设置 target triple
ifeq ($(ARCH), riscv64)
    TARGET := riscv64gc-unknown-none-elf
else ifeq ($(ARCH), amd64)
    TARGET := x86_64-unknown-none
else ifeq ($(ARCH), loongarch64)
    TARGET := loongarch64-unknown-none-elf
else
    $(error 不支持的架构: $(ARCH). 支持: riscv64, amd64, loongarch64)
endif

# Cargo 配置
CARGO_FLAGS := --release --target $(TARGET)

# 输出路径
CARGO_OUTPUT := $(KERNEL_DIR)/target/$(TARGET)/release/kernel
KERNEL_ELF   := $(BUILD_DIR)/$(ARCH)/kernel.elf

# ============================================================================
# 用户程序编译 (init 等, 内嵌进内核)
# ============================================================================

# 编译所有 user/ 下的程序, 并将产物复制到 user/build/
user-build:
	@echo "=========================================="
	@echo "  Building user programs"
	@echo "=========================================="
	@mkdir -p $(USER_DIR)/build
	@for prog in init hello tls_test; do \
		if [ -d $(USER_DIR)/$$prog ]; then \
			echo "[USER] Building $$prog ..."; \
			cd $(USER_DIR)/$$prog && \
			cargo build --release && \
			cp target/$(USER_TARGET)/release/$$prog $(USER_DIR)/build/$$prog && \
			echo "[OK] $$prog -> user/build/$$prog"; \
		fi; \
	done

# ============================================================================
# 主要目标
# ============================================================================

# 比赛测试镜像
TESTSUITS_DIR := $(TOOLS_DIR)/testsuits-for-oskernel
SDCARD_RV     := $(TESTSUITS_DIR)/sdcard-rv.img
SDCARD_RV_XZ  := $(TESTSUITS_DIR)/sdcard-rv.img.xz
DISK_IMG      := $(ROOT_DIR)/disk.img
BIOS_IMG      := $(TOOLS_DIR)/firmware/rustsbi-qemu.bin

# QEMU 参数
QEMU_MEM  ?= 128M
QEMU_SMP  ?= 1

# 用户程序 target triple (裸机静态 ELF)
USER_TARGET := riscv64gc-unknown-none-elf

.PHONY: all build run debug clean test user-build docker

# --- 比赛评测入口 ---
