//! user/init — 系统 init 进程 (PID 1)
//!
//! 功能:
//!   1. chdir 到 /mnt/musl
//!   2. 创建 test_all.sh (磁盘镜像中不包含此文件)
//!   3. fork 出 TTY 子进程 (PID 2)
//!   4. TTY 子进程 execve busybox sh test_all.sh
//!   5. init 等待 TTY 子进程退出
//!   6. exit(0) → 内核检测到 PID 1 退出 → 自动关机

#![no_std]
#![no_main]

use core::panic::PanicInfo;

#[panic_handler]
fn panic(_: &PanicInfo) -> ! {
    loop {}
}

// ─── 系统调用封装 (内联汇编 ecall) ──────────────────────

fn syscall(id: usize, a0: usize, a1: usize, a2: usize) -> isize {
    let ret: isize;
    unsafe {
        core::arch::asm!(
            "ecall",
            inlateout("a0") a0 => ret,
            in("a1") a1,
            in("a2") a2,
            in("a7") id,
        );
    }
    ret
}

fn sys_write(fd: usize, buf: &[u8]) -> isize {
    syscall(64, fd, buf.as_ptr() as usize, buf.len())
}

fn sys_exit(code: i32) -> ! {
    syscall(93, code as usize, 0, 0);
    loop {}
}

fn sys_fork() -> isize {
    // clone(SIGCHLD, 0, 0, 0, 0)
    syscall(220, 17, 0, 0) // SIGCHLD = 17
}

fn sys_execve(path: &[u8], argv: &[usize], envp: &[usize]) -> isize {
    syscall(
        221,
        path.as_ptr() as usize,
        argv.as_ptr() as usize,
        envp.as_ptr() as usize,
    )
}

fn sys_waitpid(pid: isize, wstatus: &mut i32) -> isize {
    syscall(260, pid as usize, wstatus as *mut i32 as usize, 0)
}

fn sys_kill(pid: isize, sig: usize) -> isize {
    syscall(129, pid as usize, sig, 0)
}

fn sys_chdir(path: &[u8]) -> isize {
    syscall(49, path.as_ptr() as usize, 0, 0)
}

fn syscall6(id: usize, a0: usize, a1: usize, a2: usize, a3: usize) -> isize {
    let ret: isize;
    unsafe {
        core::arch::asm!(
            "ecall",
            inlateout("a0") a0 => ret,
            in("a1") a1,
            in("a2") a2,
            in("a3") a3,
            in("a7") id,
        );
    }
    ret
}

fn syscall5(id: usize, a0: usize, a1: usize, a2: usize, a3: usize, a4: usize) -> isize {
    let ret: isize;
    unsafe {
        core::arch::asm!(
            "ecall",
            inlateout("a0") a0 => ret,
            in("a1") a1,
            in("a2") a2,
            in("a3") a3,
            in("a4") a4,
            in("a7") id,
        );
    }
    ret
}

fn sys_openat(dirfd: isize, path: &[u8], flags: u32, mode: u32) -> isize {
    syscall6(
        56,
        dirfd as usize,
        path.as_ptr() as usize,
        flags as usize,
        mode as usize,
    )
}

fn sys_mkdirat(dirfd: isize, path: &[u8], mode: u32) -> isize {
    syscall(34, dirfd as usize, path.as_ptr() as usize, mode as usize)
}

fn sys_mount(src: &[u8], target: &[u8], flags: usize) -> isize {
    syscall5(
        40,
        src.as_ptr() as usize,
        target.as_ptr() as usize,
        0,
        flags,
        0,
    )
}

fn sys_close(fd: usize) -> isize {
    syscall(57, fd, 0, 0)
}

// ─── 输出辅助 ───────────────────────────────────────────

fn print(s: &[u8]) {
    sys_write(1, s);
}

fn print_signed(n: i32) {
    if n < 0 {
        print(b"-");
        let v = (-(n as i64)) as usize;
        print_usize(v);
    } else {
        print_usize(n as usize);
    }
}

fn print_usize(mut n: usize) {
    if n == 0 {
        print(b"0");
        return;
    }
    let mut buf = [0u8; 20];
    let mut i = 0;
    while n > 0 {
        buf[i] = b'0' + (n % 10) as u8;
        n /= 10;
        i += 1;
    }
    let mut j = 0;
    while j < i / 2 {
        let tmp = buf[j];
        buf[j] = buf[i - 1 - j];
        buf[i - 1 - j] = tmp;
        j += 1;
    }
    sys_write(1, &buf[..i]);
}

