    let fd = sys_openat(AT_FDCWD, path, O_CREAT | O_WRONLY | O_TRUNC, mode);
    if fd < 0 {
        return false;
    }

    let written = sys_write(fd as usize, content);
    sys_close(fd as usize);
    written == content.len() as isize
}

