use super::manager::MANAGER;
/// sched/query.rs — 任务状态查询与访问器
///
/// 从 manager.rs 拆分而来:
/// - current_parent_pid(): 查询当前进程的父 PID
/// - with_current_addr_space(): 访问当前进程的地址空间
/// - with_current_signal(): 访问当前进程的信号状态
/// - set_task_satp(): 设置指定任务的 satp_val
/// - ready_count(): 查询就绪队列长度
use crate::hal::irq;
use crate::mm::address_space::AddressSpace;

/// 查询当前运行任务的父进程 PID
pub fn current_parent_pid() -> usize {
    let guard = irq::disable();
    let ppid = unsafe {
        let cur = MANAGER.current;
        match MANAGER.tasks[cur].as_ref() {
            Some(tcb) => tcb.parent_pid,
            None => 0,
        }
    };
    irq::restore(guard);
    ppid
}

/// 访问当前任务的地址空间 (用于 sys_brk 等)
pub fn with_current_addr_space<F, R>(f: F) -> Option<R>
where
    F: FnOnce(&mut AddressSpace) -> R,
{
    let guard = irq::disable();
    let result = unsafe {
        let cur = MANAGER.current;
        if cur == 0 {
            irq::restore(guard);
            return None;
        }
        let tcb = match MANAGER.tasks[cur].as_ref() {
            Some(t) => t,
            None => {
                irq::restore(guard);
                return None;
            }
        };
        let owner = tcb.addr_space_owner;
        let owner_tcb = match MANAGER.tasks[owner].as_mut() {
            Some(t) => t,
            None => {
                irq::restore(guard);
                return None;
            }
        };
        let addr_space = match owner_tcb.addr_space.as_mut() {
            Some(a) => a,
            None => {
                irq::restore(guard);
                return None;
            }
        };
        Some(f(addr_space))
    };
    irq::restore(guard);
    result
}

/// 访问当前任务的信号状态 (用于 rt_sigaction / rt_sigprocmask)
pub fn with_current_signal<F>(f: F) -> isize
where
    F: FnOnce(&mut crate::sched::signal::SignalState) -> isize,
{
    let guard = irq::disable();
    let result = unsafe {
        let cur = MANAGER.current;
        if cur == 0 {
            -crate::errno::ESRCH
        } else {
            match MANAGER.tasks[cur].as_mut() {
                Some(tcb) => f(&mut tcb.signal),
                None => -crate::errno::ESRCH,
            }
        }
    };
    irq::restore(guard);
    result
}

/// 以只读方式访问当前任务 TCB
pub fn with_current_tcb<F, R>(f: F) -> Option<R>
where
    F: FnOnce(&crate::sched::task::TaskControlBlock) -> R,
{
    let guard = irq::disable();
    let result = unsafe {
        let cur = MANAGER.current;
        if cur == 0 {
            None
        } else {
            MANAGER.tasks[cur].as_ref().map(f)
        }
    };
    irq::restore(guard);
    result
}

/// 设置指定任务的 satp_val (测试用)
pub fn set_task_satp(pid: usize, satp: usize) {
    let guard = irq::disable();
    unsafe {
        assert!(
            pid > 0 && pid < crate::sched::task::MAX_TASKS,
            "set_task_satp: invalid pid"
        );
        let tcb = MANAGER.tasks[pid]
            .as_mut()
            .expect("set_task_satp: no such task");
        tcb.satp_val = satp;
    }
    irq::restore(guard);
}

/// 查询当前运行任务的 PID
pub fn current_pid() -> usize {
    unsafe { MANAGER.current }
}

/// 查询当前运行任务的内核栈顶地址 (用于 sscratch 断言)
///
/// 返回 0 表示当前是 idle 或无 TCB
pub fn current_kstack_top() -> usize {
    unsafe {
        let cur = MANAGER.current;
        if cur == 0 { return 0; }
        match MANAGER.tasks[cur].as_ref() {
            Some(tcb) => tcb.kstack_top,
            None => 0,
        }
    }
}

/// 查询当前运行任务的地址空间所有者 PID
pub fn current_address_space_owner() -> usize {
    unsafe {
        let cur = MANAGER.current;
        if cur == 0 { return 0; }
        match MANAGER.tasks[cur].as_ref() {
            Some(tcb) => tcb.addr_space_owner,
            None => 0,
        }
    }
}

/// 查询就绪队列中的任务数量 (测试用)
#[allow(dead_code)]
pub fn ready_count() -> usize {
    unsafe { MANAGER.queue_count }
}

// ─── 安全查询 API (供 procfs 等外部模块使用) ────────────

/// 检查指定 PID 的任务是否存在
pub fn task_exists(pid: usize) -> bool {
    if pid >= crate::sched::task::MAX_TASKS {
        return false;
    }
    let guard = irq::disable();
    let exists = unsafe { MANAGER.tasks[pid].is_some() };
    irq::restore(guard);
    exists
}

/// 以只读方式访问指定 PID 的任务, 返回闭包结果
pub fn with_task<F, R>(pid: usize, f: F) -> Option<R>
where
    F: FnOnce(&crate::sched::task::TaskControlBlock) -> R,
{
    if pid >= crate::sched::task::MAX_TASKS {
        return None;
    }
    let guard = irq::disable();
    let result = unsafe {
        match MANAGER.tasks[pid].as_ref() {
            Some(tcb) => Some(f(tcb)),
            None => None,
        }
    };
    irq::restore(guard);
    result
}

/// 收集所有活跃任务的 PID, 写入 buf, 返回实际写入数量
pub fn collect_active_pids(buf: &mut [usize]) -> usize {
    let guard = irq::disable();
    let mut count = 0;
    unsafe {
        for pid in 1..crate::sched::task::MAX_TASKS {
            if count >= buf.len() {
                break;
            }
            if MANAGER.tasks[pid].is_some() {
                buf[count] = pid;
                count += 1;
            }
        }
    }
    irq::restore(guard);
    count
}

/// 检查当前任务是否有会中断阻塞 syscall 的待处理信号。
pub fn current_has_interrupting_signal() -> bool {
    let guard = irq::disable();
    let result = unsafe {
        let cur = MANAGER.current;
        if cur == 0 {
            false
        } else {
            match MANAGER.tasks[cur].as_ref() {
                Some(tcb) => tcb.signal.has_interrupting_pending(),
                None => false,
            }
        }
    };
    irq::restore(guard);
    result
}
